/// A single substrate-encoded coordinate: x = Q_component + R_remainder.
///
/// Register: D.5.1-DIM.
/// Invariant: |R_remainder| ≤ δ/2. Violation → Integrity Sentinel.
#[derive(Debug, Clone, PartialEq)]
pub struct SubstrateCoord {
    /// Q_component = Π_δ(x) — nearest lattice point. Stored as exact rational.
    pub q_component: Q,
    /// R_remainder = x − Π_δ(x). Must satisfy |R| ≤ δ/2.
    pub r_remainder: Q,
}

impl SubstrateCoord {
    /// Reconstruct x exactly: x = Q + R. Register: D.REMAIN.3.
    pub fn reconstruct(&self) -> Q {
        &self.q_component + &self.r_remainder
    }

    /// Check Integrity Sentinel: |R| ≤ δ/2. Register: D.5.1-DIM.
    /// Returns `Err` with coordinate index and values if sentinel fires.
    pub fn check_sentinel(&self, delta: &Q, coord_idx: usize)
        -> Result<(), SaiosError>
    {
        let half_delta = delta / &Q::new(BigInt::from(2), BigInt::from(1));
        let abs_r = self.r_remainder.abs();
        if abs_r > half_delta {
            Err(SaiosError::C1IntegritySentinel {
                coord:     coord_idx,
                remainder: self.r_remainder.clone(),
                delta:     delta.clone(),
            })
        } else {
            Ok(())
        }
    }
}

/// Encode x ∈ ℚ using grid resolution δ into (Q, R) pair.
///
/// Uses half-even (banker's) rounding per U.CHAIN.1 corrected form.
/// Register: D.5.1-DIM, D.REMAIN.1, U.CHAIN.1.
pub fn substrate_encode(x: &Q, delta: &Q) -> Result<SubstrateCoord, SaiosError> {
    if delta.is_zero() {
        return Err(SaiosError::SubstrateEncodingFailed);
    }
    // scaled = x / δ
    let scaled = x / delta;
    // Half-even round: determine floor and fractional part
    let floor_val = scaled.floor();
    let frac = &scaled - &floor_val;
    let one_half = Q::new(BigInt::from(1), BigInt::from(2));

    let rounded_int: BigInt = if frac == one_half {
        // Banker's rounding: round to even
        let f = floor_val.to_integer();
        let is_odd = &f % BigInt::from(2) != BigInt::from(0);
        if is_odd { f + BigInt::from(1) } else { f }
    } else if frac > one_half {
        floor_val.to_integer() + BigInt::from(1)
    } else {
        floor_val.to_integer()
    };

    // Q_component = rounded_int × δ  (exact rational)
    let q_component = Q::from_integer(rounded_int) * delta;
    let r_remainder = x - &q_component;

    Ok(SubstrateCoord { q_component, r_remainder })
}

/// Decode (Q, R) pair back to x exactly. Register: D.REMAIN.3.
#[inline]
pub fn substrate_decode(coord: &SubstrateCoord) -> Q {
    coord.reconstruct()
}

