// RELATIONAL DIFFERENTIAL  (D.1)
// ─────────────────────────────────────────────────────────────────────────────

/// Δ_ij — antisymmetric relational differential. Register: D.1.
///
/// Invariants (enforced on construction and after every operator application):
/// - Antisymmetry: Δ_ij = −Δ_ji
/// - Zero diagonal: Δ_ii = 0
/// - All entries ∈ ℚ^m (exact rational)
#[derive(Debug, Clone, PartialEq)]
pub struct Delta {
    /// `dim` — number of states n. Δ is n×n matrix.
    pub dim: usize,
    /// `m` — coordinate dimension of each entry (Δ_ij ∈ ℚ^m).
    pub m: usize,
    /// Row-major storage. Entry (i,j,l) = `entries[i][j][l]`.
    /// Antisymmetry: entries[i][j] = -entries[j][i].
    pub entries: Vec<Vec<QVec>>,
    /// Substrate-encoded form for B_S layer (optional, populated by encoder).
    pub encoded: Option<Vec<Vec<Vec<SubstrateCoord>>>>,
}

impl Delta {
    /// Create a new zero Delta (all entries zero).
    pub fn zero(dim: usize, m: usize) -> Self {
        let zero_vec = vec![Q::zero(); m];
        let entries = vec![vec![zero_vec; dim]; dim];
        Delta { dim, m, entries, encoded: None }
    }

    /// Get entry Δ_ij as a &QVec.
    pub fn get(&self, i: usize, j: usize) -> &QVec {
        &self.entries[i][j]
    }

    /// Set Δ_ij = v and Δ_ji = -v (enforces antisymmetry).
    /// Panics if i == j and v ≠ 0 (zero diagonal required).
    pub fn set_antisym(&mut self, i: usize, j: usize, v: QVec) {
        assert!(i < self.dim && j < self.dim, "index out of range");
        assert_eq!(v.len(), self.m, "dimension mismatch");
        if i == j {
            assert!(v.iter().all(|x| x.is_zero()), "Δ_ii must be 0");
        }
        let neg_v: QVec = v.iter().map(|x| -x).collect();
        self.entries[i][j] = v;
        self.entries[j][i] = neg_v;
    }

    // ── Temporal Anchor: Delta serialization ──────────────────────────
    //
    // The temporal anchor is the serialized Δ_k — the node's exact
    // algebraic position at a given K-step. Persists across restarts
    // so the node resumes from its evolved state, not from genesis.
    //
    // Format: dim (u32 LE) | m (u32 LE) | for each (i,j) where i<j:
    //   for each l in 0..m:
    //     numer_sign (u8: 0=zero, 1=pos, 2=neg) | numer_len (u32 LE) | numer_bytes
    //     | denom_len (u32 LE) | denom_bytes
    //
    // Antisymmetry is reconstructed on load (Δ_ji = -Δ_ij).
    // Diagonal is always zero (A.2).

    /// Serialize Delta to binary for temporal anchor persistence.
    /// Only stores upper triangle (i < j) — antisymmetry reconstructed on load.
    pub fn to_temporal_anchor(&self) -> Vec<u8> {
        let mut buf = Vec::new();
        buf.extend_from_slice(&(self.dim as u32).to_le_bytes());
        buf.extend_from_slice(&(self.m as u32).to_le_bytes());

        for i in 0..self.dim {
            for j in (i + 1)..self.dim {
                for l in 0..self.m {
                    let q = &self.entries[i][j][l];
                    let (sign, numer_bytes) = {
                        let (sign, mag) = q.numer().to_bytes_le();
                        let sign_byte = match sign {
                            num_bigint::Sign::NoSign => 0u8,
                            num_bigint::Sign::Plus => 1u8,
                            num_bigint::Sign::Minus => 2u8,
                        };
                        (sign_byte, mag)
                    };
                    let denom_bytes = q.denom().to_bytes_le().1;

                    buf.push(sign);
                    buf.extend_from_slice(&(numer_bytes.len() as u32).to_le_bytes());
                    buf.extend_from_slice(&numer_bytes);
                    buf.extend_from_slice(&(denom_bytes.len() as u32).to_le_bytes());
                    buf.extend_from_slice(&denom_bytes);
                }
            }
        }
        buf
    }

    /// Restore Delta from temporal anchor binary.
    /// Reconstructs antisymmetry (Δ_ji = -Δ_ij) and zero diagonal.
    pub fn from_temporal_anchor(data: &[u8]) -> Option<Self> {
        if data.len() < 8 { return None; }
        let dim = u32::from_le_bytes(data[0..4].try_into().ok()?) as usize;
        let m = u32::from_le_bytes(data[4..8].try_into().ok()?) as usize;
        if dim == 0 || m == 0 { return None; }

        let mut delta = Delta::zero(dim, m);
        let mut pos = 8usize;

        for i in 0..dim {
            for j in (i + 1)..dim {
                let mut v = Vec::with_capacity(m);
                for _l in 0..m {
                    if pos >= data.len() { return None; }
                    let sign_byte = data[pos]; pos += 1;

                    if pos + 4 > data.len() { return None; }
                    let numer_len = u32::from_le_bytes(data[pos..pos+4].try_into().ok()?) as usize;
                    pos += 4;
                    if pos + numer_len > data.len() { return None; }
                    let numer_bytes = &data[pos..pos+numer_len]; pos += numer_len;

                    if pos + 4 > data.len() { return None; }
                    let denom_len = u32::from_le_bytes(data[pos..pos+4].try_into().ok()?) as usize;
                    pos += 4;
                    if pos + denom_len > data.len() { return None; }
                    let denom_bytes = &data[pos..pos+denom_len]; pos += denom_len;

                    let sign = match sign_byte {
                        0 => num_bigint::Sign::NoSign,
                        1 => num_bigint::Sign::Plus,
                        2 => num_bigint::Sign::Minus,
                        _ => return None,
                    };
                    let numer = BigInt::from_bytes_le(sign, numer_bytes);
                    let denom = BigInt::from_bytes_le(num_bigint::Sign::Plus, denom_bytes);
                    if denom.is_zero() { return None; }
                    v.push(Q::new(numer, denom));
                }
                delta.set_antisym(i, j, v);
            }
        }

        Some(delta)
    }

    /// Verify antisymmetry and zero diagonal. Register: conservation invariant.
    pub fn verify_conservation(&self) -> bool {
        for i in 0..self.dim {
            // Zero diagonal
            if !self.entries[i][i].iter().all(|x| x.is_zero()) {
                return false;
            }
            for j in (i + 1)..self.dim {
                // Δ_ij + Δ_ji = 0
                for l in 0..self.m {
                    if &self.entries[i][j][l] + &self.entries[j][i][l] != Q::zero() {
                        return false;
                    }
                }
            }
        }
        true
    }
}

