/// The five φ_k invariant observables. Register: D.SYSTEM.2, D.SYSTEM.6.
///
/// C7 TRIPLE LOCK checks observables 1-3 (magnitude bounded, conservation exact, rank exact).
/// Observable 4 (symmetry_class_rcf_hash) is NOT checked at C7 — orbit transitions are the
/// mechanism of coherence minimization. RCF hash is used for between-node divergence detection
/// in the mesh layer (MeshReceipt.rcf_identity), not within-node step validation.
/// Register: D.8, T.FOUND.3.
#[derive(Debug, Clone, PartialEq)]
pub struct PhiK {
    /// I^(1): magnitude ‖Δ‖²_Q. Checked at C7 with bounded tolerance.
    pub magnitude_sq: Q,
    /// I^(2): conservation — bool confirming antisymmetry + zero diagonal.
    pub conservation_ok: bool,
    /// I^(3): rank — dimensionality of relational structure.
    pub rank: usize,
    /// I^(4): symmetry class — RCF canonical form hash (bytes).
    /// Register: D.CHAIN.ORBIT.1 (RCF, not HNF — ORBIT.1 correction applied).
    pub symmetry_class_rcf_hash: [u8; 32],
    /// I^(5): T_k chronometric magnitude. Register: CD.1-SQ.
    pub t_k: Q,
}

/// Compute φ_k(Δ) — extract all five invariant observables.
///
/// T_k is passed in as an argument because it is computed in the executor
/// loop and depends on Π_G(U(Δ_k)) which requires the update operator U.
/// Register: D.SYSTEM.2.
pub fn compute_phi_k(delta: &Delta, t_k: Q) -> PhiK {
    let magnitude_sq = phi_norm_sq_delta(delta);
    let conservation_ok = delta.verify_conservation();
    let rank = compute_rank(delta);
    let symmetry_class_rcf_hash = compute_rcf_hash(delta);
    PhiK { magnitude_sq, conservation_ok, rank, symmetry_class_rcf_hash, t_k }
}

/// φ-norm squared: ‖Δ‖²_Q = Σ_{i,j,l} Δ_ij^l². Register: D.1.
pub fn phi_norm_sq_delta(delta: &Delta) -> Q {
    let mut acc = Q::zero();
    for i in 0..delta.dim {
        for j in 0..delta.dim {
            for l in 0..delta.m {
                let v = &delta.entries[i][j][l];
                if v < &Q::zero() { acc -= v; } else { acc += v; }
            }
        }
    }
    acc
}

/// Compute matrix rank via rational Gaussian elimination. Register: φ_k obs 3.
pub fn compute_rank(delta: &Delta) -> usize {
    if delta.dim == 0 || delta.m == 0 { return 0; }
    // Flatten Δ into an (n²) × m matrix and compute rank
    let rows: usize = delta.dim * delta.dim;
    let cols: usize = delta.m;
    let mut mat: Vec<Vec<Q>> = Vec::with_capacity(rows);
    for i in 0..delta.dim {
        for j in 0..delta.dim {
            mat.push(delta.entries[i][j].clone());
        }
    }
    rational_rank(&mat, rows, cols)
}

/// Rational Gaussian elimination to compute rank. Exact — no pivoting errors.
fn rational_rank(mat: &[Vec<Q>], rows: usize, cols: usize) -> usize {
    let mut work: Vec<Vec<Q>> = mat.to_vec();
    let mut rank = 0usize;
    let mut pivot_col = 0usize;
    let mut pivot_row = 0usize;
    while pivot_row < rows && pivot_col < cols {
        // Find non-zero pivot in this column
        let mut found = None;
        for r in pivot_row..rows {
            if !work[r][pivot_col].is_zero() { found = Some(r); break; }
        }
        match found {
            None => { pivot_col += 1; continue; }
            Some(r) => {
                work.swap(pivot_row, r);
                let piv = work[pivot_row][pivot_col].clone();
                // Eliminate below
                for r2 in (pivot_row + 1)..rows {
                    if !work[r2][pivot_col].is_zero() {
                        let factor = work[r2][pivot_col].clone() / piv.clone();
                        for c in pivot_col..cols {
                            let sub = factor.clone() * work[pivot_row][c].clone();
                            work[r2][c] -= sub;
                        }
                    }
                }
                rank += 1;
                pivot_row += 1;
                pivot_col += 1;
            }
        }
    }
    rank
}

/// Compute RCF canonical form hash of Δ for symmetry class I^(4).
/// Register: D.CHAIN.ORBIT.1 — RCF (not HNF) as orbit canonical form.
///
/// Full RCF computation is deferred to saios-fabric-rcf crate.
/// Here we produce a deterministic 32-byte hash over the Δ entries
/// using the canonical rational encoding (enc(p/q) = int64(p) || uint64(q)).
/// Production implementation MUST call saios_fabric_rcf::rcf::compute_rcf()
/// before hashing.
///
/// Compute the RCF hash of a Delta: the Keccak-256 of the invariant factor
/// decomposition. Two Deltas in the same GL_n(Q) conjugacy class produce
/// the identical hash. Register: D.CHAIN.ORBIT.1, OI.FOUND.1.
pub fn compute_rcf_hash(delta: &Delta) -> [u8; 32] {
    rcf::compute_rcf_hash_from_delta(&delta.entries, delta.dim, delta.m)
}

// ─────────────────────────────────────────────────────────────────────────────
// COHERENCE FUNCTIONAL  (T.FOUND.2)
// ─────────────────────────────────────────────────────────────────────────────

/// The cocycle triple iterator — the SINGLE SOURCE of the foundational computation.
///
/// Iterates over all distinct triples (i,j,k) and all coordinate indices l,
/// computing the cocycle residual R_{ijk,l} = Δ_{ik,l} - Δ_{ij,l} - Δ_{jk,l}.
///
/// Calls `f(i, j, k, l, residual)` for each non-zero residual.
/// Every consumer of the cocycle condition calls this ONE function:
///   coherence_functional → f = |r| acc += r²
///   gradient             → f = |r| acc += r × perturbation(r, direction)
///   hessian              → f = |r| acc += perturbation(r, d1) × perturbation(r, d2)
///   decompose            → f = |r| residuals.push(r)
///   resolve              → f = |r| accumulate AᵀA and Aᵀr
///
/// The algebra has ONE cocycle condition. The code has ONE computation of it.
///
/// Register: T.FOUND.2 (cocycle condition), A.1 (exact rational).
#[inline]
pub fn for_each_residual<F>(delta: &Delta, mut f: F)
where F: FnMut(usize, usize, usize, usize, &Q)
{
    let n = delta.dim;
    let m = delta.m;
    for i in 0..n {
        for j in 0..n {
            if j == i { continue; }
            for k in 0..n {
                if k == i || k == j { continue; }
                for l in 0..m {
                    let residual = &delta.entries[i][k][l]
                        - &delta.entries[i][j][l]
                        - &delta.entries[j][k][l];
                    if !residual.is_zero() {
                        f(i, j, k, l, &residual);
                    }
                }
            }
        }
    }
}

/// First-order perturbation of Δ_{pq,l} under A = I + ε·E_{rs}.
///
/// ∂(AΔA⁻¹)_{pq,l}/∂ε|_{ε=0} = δ_{pr}·Δ_{sq,l} - δ_{qs}·Δ_{pr,l}
///
/// Single source — used by gradient, hessian, and coordinator resolution.
///
/// Register: D.AGENT.9 (gradient), D.COORD.1 (resolution).
#[inline]
pub fn perturbation(delta: &Delta, p: usize, q: usize, l: usize, r: usize, s: usize) -> Q {
    let mut result = Q::zero();
    if p == r { result = &result + &delta.entries[s][q][l]; }
    if q == s { result = &result - &delta.entries[p][r][l]; }
    result
}

/// Perturbation of a cocycle residual R_{ijk,l} by operator direction (r,s).
///
/// ∂R_{ijk,l}/∂ε_{rs} = ∂Δ_{ik}/∂ε - ∂Δ_{ij}/∂ε - ∂Δ_{jk}/∂ε
///
/// Composed from the single perturbation function above.
#[inline]
pub fn residual_perturbation(delta: &Delta, i: usize, j: usize, k: usize, l: usize, r: usize, s: usize) -> Q {
    let d_ik = perturbation(delta, i, k, l, r, s);
    let d_ij = perturbation(delta, i, j, l, r, s);
    let d_jk = perturbation(delta, j, k, l, r, s);
    &d_ik - &d_ij - &d_jk
}

/// C(Δ) = Σ_{i,j,k distinct} ‖Δ_{ik} − (Δ_{ij} + Δ_{jk})‖²_Q
///
/// Register: T.FOUND.2 — C(Δ) ≥ 0, Q-rational, = 0 iff cocycle condition.
/// C(Δ) = 0 ⟺ Δ_{ik} = Δ_{ij} + Δ_{jk} for all triples.
///
/// Built on for_each_residual — the single source of the triple iteration.
pub fn coherence_functional(delta: &Delta) -> Q {
    let mut c = Q::zero();
    for_each_residual(delta, |_i, _j, _k, _l, r| {
        if r < &Q::zero() { c -= r; } else { c += r; }
    });
    c
}

