/// Species marker for genome serialization.
pub const GENOME_SPECIES_WITNESS: u32 = 1;

/// Species marker for the chronometric authority.
/// Timekeepers observe the collective state of the mesh and write immutable
/// receipts to the chain. They do not think, derive, or compose.
pub const GENOME_SPECIES_TIMEKEEPER: u32 = 2;

/// The witness's genome — its identity, origin, and evolved position.
///
/// The genome replaces the raw temporal anchor. It carries:
/// - Species: what kind of entity (witness, agent, etc.)
/// - Generation: which cohort (era 1, era 2, etc.)
/// - Birth polynomial: the H^1 coefficients at genesis (immutable identity)
/// - Evolved Delta: the coboundary-reduced current position (mutable state)
///
/// Serialization format (self-describing, no marker files):
///   [magic: u32 = 0x47454E45 "GENE"]
///   [species: u32]
///   [generation: u32]
///   [dim: u32][m: u32]
///   [birth polynomial: n_coeffs(u32) + Q entries]
///   [evolved Delta: temporal anchor format]
#[derive(Debug, Clone)]
pub struct Genome {
    /// What kind of entity: witness, agent, etc.
    pub species: u32,
    /// Which cohort: generation 1, 2, etc.
    pub generation: u32,
    /// Immutable identity: H^1 coefficients at genesis.
    pub birth_polynomial: Vec<Q>,
    /// Current position: coboundary-reduced Delta.
    pub evolved: Delta,
    /// Crystallized knowledge: orbit axioms the witness has learned.
    /// Binary-encoded MeshKnowledge (opaque bytes, decoded by membrane module).
    pub knowledge: Vec<u8>,
    /// Trajectory comprehension: last_coherence, velocity, holonomics.
    pub trajectory: Trajectory,
    /// Environment capacity: max Delta dimension the witness can sustain.
    /// Measured at startup from available memory. Evolves toward ceiling.
    /// The witness won't accept work with dimension > capacity.
    pub capacity: u16,
    /// L3 Holonomic: Crystallized torsion markers — genomic symmetry alleles.
    /// Each (torsion_order, quality) pair represents a symmetry class this witness
    /// has crystallized at ≥99.999% confidence. These are permanent traits — the
    /// witness is "tuned" to perceive these symmetry classes. During vision,
    /// matching symmetry elements receive harmonic amplification from the genome.
    pub torsion_markers: Vec<(u16, Q)>,
    /// L3 Holonomic: Crystallized value cocycles — residual obstructions.
    /// Each (from_value, to_value, quality) triple represents a value transition
    /// this witness has crystallized across L2 consensus. The cocycle is the
    /// algebraic invariant: WHAT transmutes, not WHERE. The spatial anchor is L1.
    /// These compose with torsion markers: torsion = spatial symmetry,
    /// value_cocycles = spectral transition. Together they form the complete
    /// holonomic operator φ = (π_spatial, f_value).
    pub value_cocycles: Vec<(i16, i16, Q)>,
    /// Mathematical primitives: the composable generators of the mathematical group.
    /// Each primitive is an operation that the peel loop can compose through A.4.
    /// Sacred from genesis — the witness is born knowing all of mathematics
    /// as composable operations, not as lookup tables.
    pub math_primitives: Vec<MathPrimitive>,
    /// Spatial cochain primitives: universal spatial geometry templates.
    /// The genome holds the template (reflection exists). The membrane
    /// learns the parameter (reflect across row 5). Sacred from genesis.
    pub spatial_primitives: Vec<SpatialPrimitive>,
    /// Solved orbit registry: orbit prefixes where this witness achieved 1/1.
    /// Not a solution — just a record that the orbit was solved.
    /// External tooling reads this for distribution, drill targeting, regression.
    /// Max 128 entries. Deduplicated on insert.
    pub solved_puzzles: Vec<[u8; 4]>,
    /// Lineage depth: 0 = witness (founding), 1 = elder (created by witness), 2 = child (created by elder).
    /// Determines creation bounds: witness creates ≤2 elders, elder creates ≤3 children, child creates none.
    pub lineage_depth: u8,
    /// Parent witness ID. 0 = no parent (founding witness).
    pub parent_id: u16,
    /// Number of offspring this node has created. Saturates at tier bound.
    pub created_count: u8,
    /// The orbit that triggered this node's creation. [0;4] = genesis.
    pub birth_orbit: [u8; 4],
    /// Crystallized composed operators — vocabulary expansion through lineage.
    /// Each entry is a spatial primitive + parameter + post-spatial value map (σ_post).
    /// Discovered by the compositor, inscribed by elders, inherited by children.
    /// The peel loop reads these as direct generators — no recursive composition needed.
    /// Max 32 entries. The alphabet stays fixed. The words grow.
    pub composed_operators: Vec<ComposedOperator>,
}

/// A crystallized composed operator — a word in the algebraic vocabulary.
/// The compositor synthesizes these from the residual (spatial remap + value map).
/// The genome carries them. The peel loop applies them directly.
/// The σ_post is the entangled value map: source_value → target_value after spatial remap.
/// The score tracks total C(T) reduction achieved — the operator's lifetime utility.
#[derive(Debug, Clone)]
pub struct ComposedOperator {
    /// Spatial primitive opcode (SpatialPrimitive::to_opcode).
    pub opcode: u8,
    /// Derived parameter for the spatial primitive (e.g., axis row/col).
    pub parameter: i64,
    /// Post-spatial value map: (source_value, target_value).
    /// Applied after the spatial remap. Vec with .find() — no HashMap.
    pub sigma: Vec<(i16, i16)>,
    /// Cumulative C(T) reduction across all applications. i64, not f64 — Core Design Law 4.
    /// The operator's right to occupy a genome slot is proportional to this value.
    pub score: i64,
}

/// A composable mathematical operation — a generator of the algebraic group.
/// The genome holds these as sacred knowledge. The peel loop composes them.
/// The membrane learns WHEN to apply which primitive. The epigenome tunes
/// which primitives to attend to.
#[derive(Debug, Clone)]
pub enum MathPrimitive {
    /// n → n + k. Generates all addition. k is derived from context.
    Successor,
    /// n → -n (or max_val - n). Generates complement/inversion.
    Inverse,
    /// n → n × k mod domain. Generates scaling in finite fields.
    Scale,
    /// n → n mod k. Generates modular arithmetic / cyclic groups.
    Modulo,
    /// (a, b) → |a - b|. Generates metric/distance.
    Distance,
    /// i → axis - i. Generates spatial reflection/symmetry.
    Reflect,
    /// cell → set of adjacent cell values. Generates topological context.
    Neighbors,
    /// set → |set|. Generates cardinality/counting.
    Count,
    /// cluster → edge cells (χ < 1). Generates boundary detection.
    Boundary,
    /// (a, b) → b - a. Generates difference/rate of change.
    Delta,
    /// (f, g) → f ∘ g. Generates all higher composition.
    Compose,
}

impl MathPrimitive {
    /// The full set of mathematical generators — sacred from genesis.
    pub fn all() -> Vec<MathPrimitive> {
        vec![
            MathPrimitive::Successor,
            MathPrimitive::Inverse,
            MathPrimitive::Scale,
            MathPrimitive::Modulo,
            MathPrimitive::Distance,
            MathPrimitive::Reflect,
            MathPrimitive::Neighbors,
            MathPrimitive::Count,
            MathPrimitive::Boundary,
            MathPrimitive::Delta,
            MathPrimitive::Compose,
        ]
    }

    /// Serialize to u8 opcode.
    pub fn to_opcode(&self) -> u8 {
        match self {
            MathPrimitive::Successor  => 0,
            MathPrimitive::Inverse    => 1,
            MathPrimitive::Scale      => 2,
            MathPrimitive::Modulo     => 3,
            MathPrimitive::Distance   => 4,
            MathPrimitive::Reflect    => 5,
            MathPrimitive::Neighbors  => 6,
            MathPrimitive::Count      => 7,
            MathPrimitive::Boundary   => 8,
            MathPrimitive::Delta      => 9,
            MathPrimitive::Compose    => 10,
        }
    }

    /// Deserialize from u8 opcode.
    pub fn from_opcode(op: u8) -> Option<MathPrimitive> {
        match op {
            0  => Some(MathPrimitive::Successor),
            1  => Some(MathPrimitive::Inverse),
            2  => Some(MathPrimitive::Scale),
            3  => Some(MathPrimitive::Modulo),
            4  => Some(MathPrimitive::Distance),
            5  => Some(MathPrimitive::Reflect),
            6  => Some(MathPrimitive::Neighbors),
            7  => Some(MathPrimitive::Count),
            8  => Some(MathPrimitive::Boundary),
            9  => Some(MathPrimitive::Delta),
            10 => Some(MathPrimitive::Compose),
            _  => None,
        }
    }

    /// Apply this primitive to a cell value with context.
    /// Returns the transformed value. Context provides the second operand
    /// (neighbor values, position, cluster info) when needed.
    pub fn apply(&self, value: i64, context: &PrimitiveContext) -> i64 {
        match self {
            MathPrimitive::Successor => value + context.operand,
            MathPrimitive::Inverse => context.domain_max - value,
            MathPrimitive::Scale => {
                let k = context.operand;
                if context.domain_max > 0 { (value * k) % (context.domain_max + 1) } else { value * k }
            }
            MathPrimitive::Modulo => {
                if context.operand > 0 { value % context.operand } else { value }
            }
            MathPrimitive::Distance => (value - context.operand).abs(),
            MathPrimitive::Reflect => context.operand - value,
            MathPrimitive::Neighbors => context.neighbor_dominant,
            MathPrimitive::Count => context.neighbor_count,
            MathPrimitive::Boundary => {
                // Boundary: if cell is on boundary, return operand; else identity
                // Expressed continuously: blend toward operand by boundary_ratio
                if context.is_boundary_q.numer() > &num_bigint::BigInt::from(0) {
                    context.operand
                } else {
                    value
                }
            }
            MathPrimitive::Delta => context.operand - value,
            MathPrimitive::Compose => value, // Composition is handled at the peel loop level
        }
    }
}

/// Context for primitive application — provides the second operand
/// and environmental information for context-dependent operations.
#[derive(Debug, Clone)]
pub struct PrimitiveContext {
    /// Second operand (derived from training consensus per puzzle).
    pub operand: i64,
    /// Maximum value in the domain (for inverse, modulo).
    pub domain_max: i64,
    /// Most common value among this cell's neighbors.
    pub neighbor_dominant: i64,
    /// Count of distinct values among neighbors.
    pub neighbor_count: i64,
    /// Boundary ratio: 0 = interior, >0 = boundary (from per_cell_cohesion).
    pub is_boundary_q: Q,
}

impl PrimitiveContext {
    pub fn empty() -> Self {
        PrimitiveContext {
            operand: 0,
            domain_max: 9,
            neighbor_dominant: 0,
            neighbor_count: 0,
            is_boundary_q: Q::new(num_bigint::BigInt::from(0), num_bigint::BigInt::from(1)),
        }
    }
}

// ═══════════════════════════════════════════════════════════════════════
// SPATIAL COCHAIN PRIMITIVES — GENOMIC SCAFFOLDING FOR CELL-LEVEL SPACE
// ═══════════════════════════════════════════════════════════════════════
//
// MathPrimitives transform VALUES: f(v, ctx) → v'.
// SpatialPrimitives transform POSITIONS: π(r, c, param) → (r', c').
//
// The genome holds the template (reflection EXISTS as a possibility).
// The membrane learns the parameter (reflect across row 5).
// The peel loop generates candidates: output[r,c] = input[π(r, c, param)].
// C(T) selects. No boolean gates.
//
// These are universal spatial cochains — they exist in any grid geometry.
// The parameter space is bounded by grid dimensions, not domain_max.

/// A spatial cochain primitive — a generator of the spatial permutation group.
/// Maps output position to source position. The genome holds these as
/// sacred knowledge of spatial geometry. The membrane learns the parameters.
#[derive(Debug, Clone)]
pub enum SpatialPrimitive {
    /// Reflect across horizontal axis at row `p`: (r, c) → (2p - r, c).
    /// Generates vertical mirror symmetry.
    ReflectH,
    /// Reflect across vertical axis at col `p`: (r, c) → (r, 2p - c).
    /// Generates horizontal mirror symmetry.
    ReflectV,
    /// Translate by `p` rows: (r, c) → (r - p, c). Wraps or clamps.
    /// Generates vertical flow / displacement.
    TranslateR,
    /// Translate by `p` cols: (r, c) → (r, c - p). Wraps or clamps.
    /// Generates horizontal flow / displacement.
    TranslateC,
    /// Morphological dilation: cell takes value from nearest non-background
    /// neighbor within distance `p`. Generates region expansion.
    Dilate,
    /// Morphological erosion: boundary cells within `p` of background
    /// become background. Generates region contraction.
    Erode,
    // ── Object-level primitives (Session 8 Surgical Strike) ──
    // These operate on individual connected components (clusters), not the whole grid.
    // The cluster mask comes from AdjacencyStructure.clusters in perception.
    // The peel loop dispatches: N clusters × M object primitives. C(T) selects.
    /// Translate a single cluster by (dr, dc). Only cells in the cluster move.
    /// Background fills the vacated cells. Param encodes target cluster index.
    ObjectTranslate,
    /// Copy a cluster to a new position. The original remains. Param encodes
    /// the source cluster index. Destination derived from training consensus.
    ObjectCopy,
    /// Flood fill within a closed boundary. Fills non-cluster cells enclosed
    /// by the cluster (β_1 > 0 = holes exist). Param encodes fill value.
    BoundaryFill,
    /// Apply a value mapping σ to one cluster only. Other cells unchanged.
    /// Param encodes the target cluster index.
    ObjectRecolor,
}

/// Context for spatial primitive application.
#[derive(Debug, Clone)]
pub struct SpatialContext {
    /// The parameter derived from training consensus (axis position, offset, radius).
    pub param: i64,
    /// Grid dimensions.
    pub rows: usize,
    pub cols: usize,
    /// Background value (most common value in grid, for dilate/erode).
    pub background: i64,
}

impl SpatialPrimitive {
    /// The full set of spatial generators — sacred from genesis.
    pub fn all() -> Vec<SpatialPrimitive> {
        vec![
            SpatialPrimitive::ReflectH,
            SpatialPrimitive::ReflectV,
            SpatialPrimitive::TranslateR,
            SpatialPrimitive::TranslateC,
            SpatialPrimitive::Dilate,
            SpatialPrimitive::Erode,
            SpatialPrimitive::ObjectTranslate,
            SpatialPrimitive::ObjectCopy,
            SpatialPrimitive::BoundaryFill,
            SpatialPrimitive::ObjectRecolor,
        ]
    }

    pub fn to_opcode(&self) -> u8 {
        match self {
            SpatialPrimitive::ReflectH        => 0,
            SpatialPrimitive::ReflectV        => 1,
            SpatialPrimitive::TranslateR      => 2,
            SpatialPrimitive::TranslateC      => 3,
            SpatialPrimitive::Dilate          => 4,
            SpatialPrimitive::Erode           => 5,
            SpatialPrimitive::ObjectTranslate => 6,
            SpatialPrimitive::ObjectCopy      => 7,
            SpatialPrimitive::BoundaryFill    => 8,
            SpatialPrimitive::ObjectRecolor   => 9,
        }
    }

    pub fn from_opcode(op: u8) -> Option<SpatialPrimitive> {
        match op {
            0 => Some(SpatialPrimitive::ReflectH),
            1 => Some(SpatialPrimitive::ReflectV),
            2 => Some(SpatialPrimitive::TranslateR),
            3 => Some(SpatialPrimitive::TranslateC),
            4 => Some(SpatialPrimitive::Dilate),
            5 => Some(SpatialPrimitive::Erode),
            6 => Some(SpatialPrimitive::ObjectTranslate),
            7 => Some(SpatialPrimitive::ObjectCopy),
            8 => Some(SpatialPrimitive::BoundaryFill),
            9 => Some(SpatialPrimitive::ObjectRecolor),
            _ => None,
        }
    }

    /// Map an output position to a source position.
    /// Returns (source_row, source_col) — where to read the value from.
    /// If the source is out of bounds, returns None (cell keeps its value).
    pub fn map_position(&self, r: usize, c: usize, ctx: &SpatialContext) -> Option<(usize, usize)> {
        match self {
            SpatialPrimitive::ReflectH => {
                // Reflect across horizontal axis at row p: r' = 2p - r
                let p = ctx.param;
                let r2 = 2 * p - r as i64;
                if r2 >= 0 && (r2 as usize) < ctx.rows && r2 as usize != r {
                    Some((r2 as usize, c))
                } else {
                    None // out of bounds or identity
                }
            }
            SpatialPrimitive::ReflectV => {
                // Reflect across vertical axis at col p: c' = 2p - c
                let p = ctx.param;
                let c2 = 2 * p - c as i64;
                if c2 >= 0 && (c2 as usize) < ctx.cols && c2 as usize != c {
                    Some((r, c2 as usize))
                } else {
                    None
                }
            }
            SpatialPrimitive::TranslateR => {
                // Translate by p rows: read from (r - p, c)
                let r2 = r as i64 - ctx.param;
                if r2 >= 0 && (r2 as usize) < ctx.rows {
                    Some((r2 as usize, c))
                } else {
                    None
                }
            }
            SpatialPrimitive::TranslateC => {
                // Translate by p cols: read from (r, c - p)
                let c2 = c as i64 - ctx.param;
                if c2 >= 0 && (c2 as usize) < ctx.cols {
                    Some((r, c2 as usize))
                } else {
                    None
                }
            }
            // Dilate/Erode operate on whole grid. Object-level primitives operate
            // on cluster subsets. Both handled in the peel loop, not per-position.
            SpatialPrimitive::Dilate | SpatialPrimitive::Erode => None,
            SpatialPrimitive::ObjectTranslate | SpatialPrimitive::ObjectCopy
            | SpatialPrimitive::BoundaryFill | SpatialPrimitive::ObjectRecolor => None,
        }
    }

    // ── Object-level primitive applications ──
    // These operate on cluster subsets of the grid. The cluster mask (cell_indices)
    // comes from AdjacencyStructure.clusters in perception. The peel loop in
    // thinking.rs dispatches: N clusters × M object primitives. C(T) selects.

    /// Translate a single cluster by (dr, dc). Vacated cells become background.
    pub fn apply_object_translate(
        grid: &[i64], rows: usize, cols: usize, background: i64,
        cluster_cells: &[usize], dr: i64, dc: i64,
    ) -> Vec<i64> {
        let n = grid.len();
        let mut result = grid.to_vec();
        // Clear source cells
        for &idx in cluster_cells {
            if idx < n { result[idx] = background; }
        }
        // Place at destination
        for &idx in cluster_cells {
            if idx >= n { continue; }
            let r = (idx / cols) as i64 + dr;
            let c = (idx % cols) as i64 + dc;
            if r >= 0 && (r as usize) < rows && c >= 0 && (c as usize) < cols {
                let di = r as usize * cols + c as usize;
                if di < n { result[di] = grid[idx]; }
            }
        }
        result
    }

    /// Copy a cluster to a new position. Original cells remain.
    pub fn apply_object_copy(
        grid: &[i64], rows: usize, cols: usize,
        cluster_cells: &[usize], dr: i64, dc: i64,
    ) -> Vec<i64> {
        let n = grid.len();
        let mut result = grid.to_vec();
        for &idx in cluster_cells {
            if idx >= n { continue; }
            let r = (idx / cols) as i64 + dr;
            let c = (idx % cols) as i64 + dc;
            if r >= 0 && (r as usize) < rows && c >= 0 && (c as usize) < cols {
                let di = r as usize * cols + c as usize;
                if di < n { result[di] = grid[idx]; }
            }
        }
        result
    }

    /// Boundary fill using pre-computed interior cells from perception.
    /// Perception's flood-fill already identified enclosed cells during betti_1
    /// computation. The engine just fills them. No topology detection here.
    pub fn apply_boundary_fill(
        grid: &[i64], interior_cells: &[usize], fill_value: i64,
    ) -> Vec<i64> {
        let n = grid.len();
        let mut result = grid.to_vec();
        for &idx in interior_cells {
            if idx < n { result[idx] = fill_value; }
        }
        result
    }

    /// Recolor a single cluster: apply value mapping σ to cluster cells only.
    pub fn apply_object_recolor(
        grid: &[i64], cluster_cells: &[usize], sigma: &[(i64, i64)],
    ) -> Vec<i64> {
        let n = grid.len();
        let mut result = grid.to_vec();
        for &idx in cluster_cells {
            if idx >= n { continue; }
            let v = grid[idx];
            let mapped = sigma.iter()
                .find(|(sv, _)| *sv == v)
                .map(|(_, tv)| *tv)
                .unwrap_or(v);
            result[idx] = mapped;
        }
        result
    }
}

// Genome v3: no magic bytes. Structure IS identity.

impl Genome {
    /// Create a new genome from a genesis Delta.
    /// The birth polynomial is extracted as the coboundary-reduced residuals.
    pub fn new(species: u32, generation: u32, genesis: &Delta) -> Self {
        let reduced = coboundary_reduce(genesis);
        // Extract nonzero entries from reduced Delta as polynomial coefficients
        let mut poly = Vec::new();
        for i in 0..reduced.dim {
            for j in (i + 1)..reduced.dim {
                for l in 0..reduced.m {
                    poly.push(reduced.entries[i][j][l].clone());
                }
            }
        }
        Genome {
            species,
            generation,
            birth_polynomial: poly,
            evolved: reduced,
            knowledge: vec![],
            trajectory: Trajectory::new(),
            capacity: 3, // genesis: start at 3×3
            torsion_markers: vec![],
            value_cocycles: vec![],
            math_primitives: MathPrimitive::all(),
            spatial_primitives: SpatialPrimitive::all(),
            solved_puzzles: vec![],
            lineage_depth: 0,
            parent_id: 0,
            created_count: 0,
            birth_orbit: [0; 4],
            composed_operators: vec![],
        }
    }

    /// Creation capacity remaining at this tier.
    /// Witness (depth 0): 3 elders. Elder (depth 1): 6 children. Child (depth 2): 0.
    pub fn creation_capacity(&self) -> u8 {
        let max = match self.lineage_depth {
            0 => 3u8,
            1 => 6u8,
            _ => 0u8,
        };
        max.saturating_sub(self.created_count)
    }

    /// Assimilate a composed operator into the genome.
    ///
    /// Score-based eviction — the 32-slot limit is a pressure boundary, not a wall.
    /// If the operator already exists: reinforce its score (accumulation).
    /// If the genome has room: append.
    /// If the genome is full: the weakest operator yields to the stronger.
    /// The variational selection pattern — `<` IS C(T). No boolean gates.
    pub fn assimilate(&mut self, op: ComposedOperator) {
        // Reinforcement: existing operator accumulates score
        self.composed_operators.iter_mut()
            .find(|ex| ex.opcode == op.opcode && ex.parameter == op.parameter)
            .map(|existing| { existing.score = existing.score.saturating_add(op.score); })
            .unwrap_or_else(|| {
                // New operator — append or evict
                (self.composed_operators.len() < 32).then(|| {
                    self.composed_operators.push(op.clone());
                }).unwrap_or_else(|| {
                    // Eviction: find the weakest, yield if new is stronger
                    self.composed_operators.iter()
                        .enumerate()
                        .min_by_key(|(_, ex)| ex.score)
                        .map(|(idx, ex)| (idx, ex.score))
                        .filter(|(_, min_score)| op.score > *min_score)
                        .map(|(idx, _)| {
                            self.composed_operators[idx] = op.clone();
                        });
                });
            });
    }

    /// Record a solved orbit. Dedup via find → dissolution. Bounded to 128.
    pub fn record_solved_puzzle(&mut self, orbit: [u8; 4]) {
        self.solved_puzzles.iter()
            .find(|o| **o == orbit)
            .map(|_| ()) // already recorded — dissolves
            .unwrap_or_else(|| {
                self.solved_puzzles.truncate(127); // capacity gate as truncation — no branch
                self.solved_puzzles.push(orbit);
            });
    }

    /// Serialize the genome to compact binary.
    ///
    /// Format v2 (compact):
    ///   [GENE magic: 4 bytes]
    ///   [species: 1 byte] [generation: 2 bytes]
    ///   [n_nonzero_poly: 1 byte]
    ///   [for each nonzero: index(1) + numer_i16(2) + denom_u16(2) = 5 bytes]
    ///   [knowledge_len: 2 bytes] [knowledge bytes]
    ///   [history_count: 2 bytes] [for each: numer_i16(2) + denom_u16(2) = 4 bytes]
    ///   [dim: 1 byte] [m: 1 byte]
    ///   [n_nonzero_delta: 1 byte]
    ///   [for each nonzero: i(1) + j(1) + l(1) + numer_i16(2) + denom_u16(2) = 7 bytes]
    pub fn to_bytes(&self) -> Vec<u8> {
        let mut buf = Vec::new();
        buf.push(self.species as u8);
        buf.extend_from_slice(&(self.generation as u16).to_le_bytes());

        // Birth polynomial — only nonzero entries
        let nonzero_poly: Vec<(u8, i16, u16)> = self.birth_polynomial.iter().enumerate()
            .filter(|(_, q)| !q.is_zero())
            .map(|(i, q)| {
                let n: i64 = q.numer().try_into().unwrap_or(0);
                let d: i64 = q.denom().try_into().unwrap_or(1);
                (i as u8, n as i16, d.unsigned_abs() as u16)
            })
            .collect();
        buf.push(nonzero_poly.len() as u8);
        for (idx, n, d) in &nonzero_poly {
            buf.push(*idx);
            buf.extend_from_slice(&n.to_le_bytes());
            buf.extend_from_slice(&d.to_le_bytes());
        }

        // Knowledge
        let k_len = self.knowledge.len().min(u16::MAX as usize);
        buf.extend_from_slice(&(k_len as u16).to_le_bytes());
        buf.extend_from_slice(&self.knowledge[..k_len]);

        // Trajectory comprehension: 3 measurements + max + mean state
        // Each Q as i16 numer + u16 denom = 4 bytes. 5 values + u32 count = 24 bytes.
        let traj = &self.trajectory;
        for q in [&traj.last_coherence, &traj.velocity, &traj.holonomics,
                  &traj.max_coherence, &traj.coherence_sum] {
            let n: i64 = q.numer().try_into().unwrap_or(0);
            let d: i64 = q.denom().try_into().unwrap_or(1);
            buf.extend_from_slice(&(n as i16).to_le_bytes());
            buf.extend_from_slice(&(d.unsigned_abs() as u16).to_le_bytes());
        }
        buf.extend_from_slice(&traj.coherence_count.to_le_bytes());

        // Environment capacity
        buf.extend_from_slice(&self.capacity.to_le_bytes());

        // L3 Torsion markers: [count: u8] [order_u16 + numer_i16 + denom_u16 per entry]
        let n_markers = self.torsion_markers.len().min(255);
        buf.push(n_markers as u8);
        for (order, quality) in self.torsion_markers.iter().take(n_markers) {
            buf.extend_from_slice(&order.to_le_bytes());
            let n: i64 = quality.numer().try_into().unwrap_or(0);
            let d: i64 = quality.denom().try_into().unwrap_or(1);
            buf.extend_from_slice(&(n as i16).to_le_bytes());
            buf.extend_from_slice(&(d.unsigned_abs() as u16).to_le_bytes());
        }

        // L3 Value cocycles: [count: u8] [from_i16 + to_i16 + numer_i16 + denom_u16 per entry]
        let n_cocycles = self.value_cocycles.len().min(255);
        buf.push(n_cocycles as u8);
        for (from_v, to_v, quality) in self.value_cocycles.iter().take(n_cocycles) {
            buf.extend_from_slice(&from_v.to_le_bytes());
            buf.extend_from_slice(&to_v.to_le_bytes());
            let n: i64 = quality.numer().try_into().unwrap_or(0);
            let d: i64 = quality.denom().try_into().unwrap_or(1);
            buf.extend_from_slice(&(n as i16).to_le_bytes());
            buf.extend_from_slice(&(d.unsigned_abs() as u16).to_le_bytes());
        }

        // Evolved Delta — compact: dim, m, nonzero entries only
        buf.push(self.evolved.dim as u8);
        buf.push(self.evolved.m as u8);
        let mut nonzero_entries: Vec<(u8, u8, u8, i16, u16)> = Vec::new();
        for i in 0..self.evolved.dim {
            for j in (i + 1)..self.evolved.dim {
                for l in 0..self.evolved.m {
                    let q = &self.evolved.entries[i][j][l];
                    if !q.is_zero() {
                        let n: i64 = q.numer().try_into().unwrap_or(0);
                        let d: i64 = q.denom().try_into().unwrap_or(1);
                        nonzero_entries.push((i as u8, j as u8, l as u8, n as i16, d.unsigned_abs() as u16));
                    }
                }
            }
        }
        buf.push(nonzero_entries.len() as u8);
        for (i, j, l, n, d) in &nonzero_entries {
            buf.push(*i); buf.push(*j); buf.push(*l);
            buf.extend_from_slice(&n.to_le_bytes());
            buf.extend_from_slice(&d.to_le_bytes());
        }

        // Math primitives: [count: u8] [opcode: u8 per entry]
        // Sacred from genesis — the witness's mathematical vocabulary.
        let n_prims = self.math_primitives.len().min(255);
        buf.push(n_prims as u8);
        for prim in self.math_primitives.iter().take(n_prims) {
            buf.push(prim.to_opcode());
        }

        // Spatial primitives: [count: u8] [opcode: u8 per entry]
        // Sacred from genesis — the witness's spatial geometry vocabulary.
        let n_spatial = self.spatial_primitives.len().min(255);
        buf.push(n_spatial as u8);
        for prim in self.spatial_primitives.iter().take(n_spatial) {
            buf.push(prim.to_opcode());
        }

        // Solved orbits: [count: u8] [orbit_4 per entry]
        let n_solved = self.solved_puzzles.len().min(128);
        buf.push(n_solved as u8);
        for orbit in self.solved_puzzles.iter().take(n_solved) {
            buf.extend_from_slice(orbit);
        }

        // Lineage: depth(1) + parent_id(2) + created_count(1) + birth_orbit(4) = 8 bytes
        buf.push(self.lineage_depth);
        buf.extend_from_slice(&self.parent_id.to_le_bytes());
        buf.push(self.created_count);
        buf.extend_from_slice(&self.birth_orbit);

        // Composed operators: [count_u8] + count × [opcode_u8 + param_i64 + score_i64 + sigma_count_u8 + sigma × (from_i16 + to_i16)]
        let n_ops = self.composed_operators.len().min(32);
        buf.push(n_ops as u8);
        for op in self.composed_operators.iter().take(n_ops) {
            buf.push(op.opcode);
            buf.extend_from_slice(&op.parameter.to_le_bytes());
            buf.extend_from_slice(&op.score.to_le_bytes());
            let n_sigma = op.sigma.len().min(255);
            buf.push(n_sigma as u8);
            op.sigma.iter().take(n_sigma).for_each(|(from_v, to_v)| {
                buf.extend_from_slice(&from_v.to_le_bytes());
                buf.extend_from_slice(&to_v.to_le_bytes());
            });
        }

        buf
    }

    /// Deserialize a genome from binary.
    pub fn from_bytes(data: &[u8]) -> Option<Self> {
        if data.len() < 3 { return None; }
        let species = data[0] as u32;
        let generation = u16::from_le_bytes(data[1..3].try_into().ok()?) as u32;

        let mut pos = 3;

        // Birth polynomial
        if pos >= data.len() { return None; }
        let n_nonzero = data[pos] as usize; pos += 1;
        // We need to know the total poly size to reconstruct.
        // The max index tells us the minimum size.
        let mut poly_entries: Vec<(usize, Q)> = Vec::new();
        let mut max_idx = 0usize;
        for _ in 0..n_nonzero {
            if pos + 5 > data.len() { return None; }
            let idx = data[pos] as usize; pos += 1;
            let n = i16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
            let d = u16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
            if d == 0 { return None; }
            poly_entries.push((idx, Q::new(BigInt::from(n as i64), BigInt::from(d as i64))));
            if idx > max_idx { max_idx = idx; }
        }
        let poly_size = if n_nonzero > 0 { max_idx + 1 } else { 0 };
        let mut poly = vec![Q::zero(); poly_size];
        for (idx, q) in poly_entries { poly[idx] = q; }

        // Knowledge
        if pos + 2 > data.len() { return None; }
        let k_len = u16::from_le_bytes(data[pos..pos+2].try_into().ok()?) as usize; pos += 2;
        let knowledge = if pos + k_len <= data.len() {
            let k = data[pos..pos+k_len].to_vec(); pos += k_len; k
        } else { vec![] };

        // Trajectory comprehension: 5 Q values (i16/u16 each) + u32 count = 24 bytes
        if pos + 24 > data.len() { return None; }
        let mut traj_vals = Vec::with_capacity(5);
        for _ in 0..5 {
            let n = i16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
            let d = u16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
            let d_val = if d == 0 { 1u16 } else { d };
            traj_vals.push(Q::new(BigInt::from(n as i64), BigInt::from(d_val as i64)));
        }
        let traj_count = u32::from_le_bytes(data[pos..pos+4].try_into().ok()?); pos += 4;
        let trajectory = Trajectory::from_genome(
            traj_vals[0].clone(), traj_vals[1].clone(), traj_vals[2].clone(),
            traj_vals[3].clone(), traj_vals[4].clone(), traj_count,
        );

        // Environment capacity (backward compatible: default 3 if missing)
        let capacity = if pos + 2 <= data.len() {
            let c = u16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
            if c == 0 { 3 } else { c }
        } else { 3 };

        // L3 Torsion markers (backward compatible: 0 markers if missing)
        let mut torsion_markers: Vec<(u16, Q)> = Vec::new();
        if pos < data.len() {
            let n_markers = data[pos] as usize; pos += 1;
            for _ in 0..n_markers {
                if pos + 6 > data.len() { break; }
                let order = u16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
                let n = i16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
                let d = u16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
                let d_val = if d == 0 { 1u16 } else { d };
                torsion_markers.push((order, Q::new(BigInt::from(n as i64), BigInt::from(d_val as i64))));
            }
        }

        // L3 Value cocycles (backward compatible: 0 if missing)
        let mut value_cocycles: Vec<(i16, i16, Q)> = Vec::new();
        if pos < data.len() {
            let n_cocycles = data[pos] as usize; pos += 1;
            for _ in 0..n_cocycles {
                if pos + 8 > data.len() { break; }
                let from_v = i16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
                let to_v = i16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
                let n = i16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
                let d = u16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
                let d_val = if d == 0 { 1u16 } else { d };
                value_cocycles.push((from_v, to_v, Q::new(BigInt::from(n as i64), BigInt::from(d_val as i64))));
            }
        }

        // Evolved Delta
        if pos + 2 > data.len() { return None; }
        let dim = data[pos] as usize; pos += 1;
        let m = data[pos] as usize; pos += 1;
        if dim == 0 || m == 0 { return None; }
        let mut evolved = Delta::zero(dim, m);
        if pos >= data.len() { return None; }
        let n_entries = data[pos] as usize; pos += 1;
        for _ in 0..n_entries {
            if pos + 7 > data.len() { break; }
            let i = data[pos] as usize; pos += 1;
            let j = data[pos] as usize; pos += 1;
            let l = data[pos] as usize; pos += 1;
            let n = i16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
            let d = u16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
            if d != 0 && i < dim && j < dim && l < m {
                let q = Q::new(BigInt::from(n as i64), BigInt::from(d as i64));
                evolved.entries[i][j][l] = q.clone();
                evolved.entries[j][i][l] = -q;
            }
        }

        // Math primitives (backward compatible: all primitives if missing)
        let math_primitives = if pos < data.len() {
            let n_prims = data[pos] as usize; pos += 1;
            let mut prims = Vec::new();
            for _ in 0..n_prims {
                if pos >= data.len() { break; }
                if let Some(prim) = MathPrimitive::from_opcode(data[pos]) {
                    prims.push(prim);
                }
                pos += 1;
            }
            prims
        } else {
            MathPrimitive::all()
        };

        // Spatial primitives (backward compatible: all spatial primitives if missing)
        let spatial_primitives = if pos < data.len() {
            let n_spatial = data[pos] as usize; pos += 1;
            let mut prims = Vec::new();
            for _ in 0..n_spatial {
                if pos >= data.len() { break; }
                if let Some(prim) = SpatialPrimitive::from_opcode(data[pos]) {
                    prims.push(prim);
                }
                pos += 1;
            }
            prims
        } else {
            SpatialPrimitive::all()
        };

        // Solved orbits (backward compatible: empty if missing)
        let mut solved_puzzles: Vec<[u8; 4]> = Vec::new();
        if pos < data.len() {
            let n_solved = data[pos] as usize; pos += 1;
            for _ in 0..n_solved.min(128) {
                if pos + 4 > data.len() { break; }
                let orbit: [u8; 4] = data[pos..pos+4].try_into().ok()?;
                solved_puzzles.push(orbit);
                pos += 4;
            }
        }

        // Lineage (backward compatible: founding witness if missing)
        let (lineage_depth, parent_id, created_count, birth_orbit) = if pos + 8 <= data.len() {
            let ld = data[pos]; pos += 1;
            let pid = u16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
            let cc = data[pos]; pos += 1;
            let bo: [u8; 4] = data[pos..pos+4].try_into().ok()?; pos += 4;
            (ld, pid, cc, bo)
        } else {
            (0u8, 0u16, 0u8, [0u8; 4])
        };

        // Composed operators (backward compatible: empty if missing)
        let mut composed_operators: Vec<ComposedOperator> = Vec::new();
        if pos < data.len() {
            let n_ops = data[pos] as usize; pos += 1;
            for _ in 0..n_ops.min(32) {
                if pos + 18 > data.len() { break; } // opcode(1) + param(8) + score(8) + sigma_count(1)
                let opcode = data[pos]; pos += 1;
                let parameter = i64::from_le_bytes(data[pos..pos+8].try_into().ok()?); pos += 8;
                let score = i64::from_le_bytes(data[pos..pos+8].try_into().ok()?); pos += 8;
                let n_sigma = data[pos] as usize; pos += 1;
                let mut sigma = Vec::with_capacity(n_sigma);
                for _ in 0..n_sigma {
                    if pos + 4 > data.len() { break; }
                    let from_v = i16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
                    let to_v = i16::from_le_bytes(data[pos..pos+2].try_into().ok()?); pos += 2;
                    sigma.push((from_v, to_v));
                }
                composed_operators.push(ComposedOperator { opcode, parameter, sigma, score });
            }
        }

        Some(Genome { species, generation, birth_polynomial: poly, evolved, knowledge, trajectory, capacity, torsion_markers, value_cocycles, math_primitives, spatial_primitives, solved_puzzles, lineage_depth, parent_id, created_count, birth_orbit, composed_operators })
    }
}

/// Coboundary reduction: project Delta onto its H^1 representative.
///
/// A coboundary is Δ_{ij} = f(j) - f(i) for some 0-cochain f.
/// Adding or removing a coboundary doesn't change any cocycle residual
/// R_{ijk} because (f(k)-f(i)) - (f(j)-f(i)) - (f(k)-f(j)) = 0.
///
/// Choose f(0) = 0, f(k) = Δ_{0k,l} for k > 0 (one f per coordinate l).
/// Then Δ'_{ij,l} = Δ_{ij,l} - Δ_{0j,l} + Δ_{0i,l}.
///
/// Result: Δ'_{0j} = 0 for all j. The remaining entries Δ'_{ij} (i,j > 0)
/// equal the cocycle residuals. The coboundary component — the accumulated
/// conjugation factors — is removed. The H^1 content is preserved exactly.
pub fn coboundary_reduce(delta: &Delta) -> Delta {
    let mut reduced = Delta::zero(delta.dim, delta.m);
    for i in 0..delta.dim {
        for j in (i + 1)..delta.dim {
            let mut coords = Vec::with_capacity(delta.m);
            for l in 0..delta.m {
                // Δ'_{ij,l} = Δ_{ij,l} - Δ_{0j,l} + Δ_{0i,l}
                // When i=0: Δ'_{0j,l} = Δ_{0j,l} - Δ_{0j,l} + Δ_{00,l} = 0 ✓
                let d_ij = &delta.entries[i][j][l];
                let d_0j = &delta.entries[0][j][l];
                let d_0i = &delta.entries[0][i][l];
                coords.push(d_ij - d_0j + d_0i);
            }
            reduced.set_antisym(i, j, coords);
        }
    }
    // Integer normalization: the H^1 class [Δ] includes all λΔ.
    // Multiply all entries by lcm of all denominators → integer Delta.
    // Divide by gcd of all numerators → reduced integer representative.
    // Exact. No approximation. Same cohomology class. denom=1 everywhere.
    let mut lcm_denom = BigInt::from(1);
    for i in 0..reduced.dim {
        for j in (i + 1)..reduced.dim {
            for l in 0..reduced.m {
                let d = reduced.entries[i][j][l].denom().clone();
                lcm_denom = num_integer::lcm(lcm_denom, d);
            }
        }
    }
    // Scale all entries to integer
    let scale = Q::new(lcm_denom.clone(), BigInt::from(1));
    let mut gcd_numer = BigInt::from(0);
    for i in 0..reduced.dim {
        for j in (i + 1)..reduced.dim {
            for l in 0..reduced.m {
                reduced.entries[i][j][l] = &reduced.entries[i][j][l] * &scale;
                reduced.entries[j][i][l] = -reduced.entries[i][j][l].clone();
                let n = reduced.entries[i][j][l].numer().clone();
                gcd_numer = num_integer::gcd(gcd_numer.clone(), n.abs());
            }
        }
    }
    // Reduce by common factor
    (gcd_numer > BigInt::from(1)).then(|| {
        let divisor = Q::new(gcd_numer, BigInt::from(1));
        for i in 0..reduced.dim {
            for j in (i + 1)..reduced.dim {
                for l in 0..reduced.m {
                    reduced.entries[i][j][l] = &reduced.entries[i][j][l] / &divisor;
                    reduced.entries[j][i][l] = -reduced.entries[i][j][l].clone();
                }
            }
        }
    });
    reduced
}

/// Count active (nonzero) entries in the upper triangle of Delta.
/// Each nonzero entry is one relational dimension — one piece of
/// information the witness holds about the relationship between
/// two entities at one coordinate. A decrease in this count means
/// dimensional collapse — structural regression.
pub fn count_active_entries(delta: &Delta) -> usize {
    let mut count = 0;
    for i in 0..delta.dim {
        for j in (i + 1)..delta.dim {
            for l in 0..delta.m {
                if !delta.entries[i][j][l].is_zero() {
                    count += 1;
                }
            }
        }
    }
    count
}

/// Compute the evolutionary displacement from genesis.
///
/// Two measurements, neither is a scalar "distance":
///
/// **drift** — the L1 norm of entry-wise displacement in independent
/// coordinates (i < j). Measures how far the node's relational structure
/// has moved from genesis through the operator space. Exact Q.
/// For 3×3 m=1: drift = |Δ_k[0][1] - Δ_gen[0][1]| + |Δ_k[1][2] - Δ_gen[1][2]|
/// (Δ[0][2] is determined by cocycle, not independent.)
///
/// **torsion** — coherence_functional(Δ_k). Measures how far off the
/// cocycle-consistent surface. A node at torsion=0 has evolved within
/// the flat surface. A node at torsion>0 carries unresolved cohomology
/// classes — independent obstructions requiring dimensional expansion.
///
/// Together: (drift, torsion) = (where in operator space, what obstructions).
/// The orbital position is not a radius — it's a coordinate in the space
/// defined by the algebra's own structure.
pub fn genesis_displacement(delta_k: &Delta, genesis: &Delta) -> (Q, Q) {
    // Drift: sum of |Δ_k[i][j][l] - Δ_genesis[i][j][l]| over independent entries
    let mut drift = Q::zero();
    let dim = delta_k.dim.min(genesis.dim);
    let m = delta_k.m.min(genesis.m);
    for i in 0..dim {
        for j in (i + 1)..dim {
            for l in 0..m {
                let diff = &delta_k.entries[i][j][l] - &genesis.entries[i][j][l];
                if diff < Q::zero() {
                    drift -= &diff;
                } else {
                    drift += &diff;
                }
            }
        }
    }

    // Torsion: C(Δ_k) — how far off the cocycle surface
    let torsion = coherence_functional(delta_k);

    (drift, torsion)
}

/// D.MEMBRANE.LIVING.1: Harmonic state — the witness's polytonal position
/// across 11 dimensions of the manifold.
///
/// Each dimension is a Q measurement of a different projection of the
/// witness's Δ_k. Together they form the chord the witness is playing.
/// Different witnesses play different chords. The membrane hears them all.
///
/// This replaces the monotonic scalar C(Δ) as the witness's self-perception.
/// The scalar is ONE tone (dimension 11). The harmonic state is all 11.
#[derive(Debug, Clone)]
pub struct HarmonicState {
    /// 11 vibrations — polytonal self-perception of Δ_k.
    /// Each vibration is a Q projection onto one dimension of the manifold.
    pub vibrations: [Q; 11],
}

impl HarmonicState {
    /// Compute the harmonic state of a witness's Δ_k.
    ///
    /// Each tone is a projection of the algebraic state onto one
    /// dimension of the manifold. Computed from the Delta's entries,
    /// its coherence history, and its evolutionary trajectory.
    pub fn from_delta(
        delta_k: &Delta,
        genesis: &Delta,
        trajectory: &Trajectory,
        _k_index: u64,
    ) -> Self {
        let dim = delta_k.dim;
        let m = delta_k.m;

        // Tone 1: Entry magnitudes — total relational energy
        let mut magnitude = Q::zero();
        for i in 0..dim {
            for j in (i + 1)..dim {
                for l in 0..m {
                    let e = &delta_k.entries[i][j][l];
                    if e < &Q::zero() { magnitude -= e; } else { magnitude += e; }
                }
            }
        }

        // Tone 2: Entry ratios — geometric shape
        // Ratio of largest to smallest non-zero entry magnitude
        let mut entries_abs: Vec<Q> = Vec::new();
        for i in 0..dim {
            for j in (i + 1)..dim {
                for l in 0..m {
                    let e = &delta_k.entries[i][j][l];
                    if !e.is_zero() {
                        let abs_e = if e < &Q::zero() { -e.clone() } else { e.clone() };
                        entries_abs.push(abs_e);
                    }
                }
            }
        }
        let shape = if entries_abs.len() >= 2 {
            let min_e = entries_abs.iter().min().cloned().unwrap_or(Q::one());
            let max_e = entries_abs.iter().max().cloned().unwrap_or(Q::one());
            if max_e.is_zero() { Q::zero() }
            else { Q::new(min_e.numer() * max_e.denom(), min_e.denom() * max_e.numer().clone()) }
        } else {
            Q::one() // single entry = no ratio
        };

        // Tone 3: Per-triple residuals — cocycle consistency distribution
        // Mean absolute residual (not squared — direct measurement)
        let mut residual_sum = Q::zero();
        let mut residual_count = 0u64;
        for_each_residual(delta_k, |_i, _j, _k, _l, r| {
            let abs_r = if r < &Q::zero() { -r.clone() } else { r.clone() };
            residual_sum += &abs_r;
            residual_count += 1;
        });
        let mean_residual = if residual_count > 0 {
            Q::new(residual_sum.numer().clone(),
                   residual_sum.denom() * BigInt::from(residual_count as i64))
        } else {
            Q::zero()
        };

        // Tone 4: Active entry density — relational attention structure
        let total_entries = (dim * (dim - 1) / 2) * m;
        let active_entries = entries_abs.len();
        let attention = if total_entries > 0 {
            Q::new(BigInt::from(active_entries as i64), BigInt::from(total_entries as i64))
        } else {
            Q::zero()
        };

        // Tone 5: Automorphism — does Δ_k have internal symmetry?
        // Check: is Δ_k invariant under any permutation of its indices?
        // For 3×3: check if swapping indices 0,1 or 1,2 preserves entries
        let mut symmetry_score = Q::zero();
        if dim >= 3 && m >= 1 {
            // Check entry equality under index permutations
            let e01 = &delta_k.entries[0][1][0];
            let e12 = &delta_k.entries[1][2][0];
            let e02 = &delta_k.entries[0][2][0];
            // Symmetry: how close are e01 and e12? (0 = identical = has symmetry)
            let diff_01_12 = e01 - e12;
            let abs_diff = if diff_01_12 < Q::zero() { -diff_01_12 } else { diff_01_12 };
            let max_entry = entries_abs.iter().max().cloned().unwrap_or(Q::one());
            if max_entry.is_zero() {
                symmetry_score = Q::one();
            } else {
                let ratio = Q::new(abs_diff.numer() * max_entry.denom(),
                                   abs_diff.denom() * max_entry.numer().clone());
                symmetry_score = if ratio > Q::one() { Q::zero() } else { Q::one() - &ratio };
            }
            // Also check cocycle consistency (e02 = e01 + e12)
            let cocycle_diff = e02 - e01 - e12;
            let abs_cocycle = if cocycle_diff < Q::zero() { -cocycle_diff } else { cocycle_diff };
            if !abs_cocycle.is_zero() && !max_entry.is_zero() {
                let coc_ratio = Q::new(abs_cocycle.numer() * max_entry.denom(),
                                       abs_cocycle.denom() * max_entry.numer().clone());
                if coc_ratio < Q::one() {
                    symmetry_score = Q::new(
                        symmetry_score.numer() * (&Q::one() - &coc_ratio).denom()
                            + (&Q::one() - &coc_ratio).numer() * symmetry_score.denom(),
                        symmetry_score.denom() * BigInt::from(2) * (&Q::one() - &coc_ratio).denom(),
                    );
                }
            }
        }

        // Tone 6: Boundary gradient — how entries change at the edge
        // For 3×3: the difference between e01 and e02 captures boundary shift
        let boundary = if dim >= 3 && m >= 1 && !entries_abs.is_empty() {
            let e01 = &delta_k.entries[0][1][0];
            let e02 = &delta_k.entries[0][2][0];
            let diff = e02 - e01;
            let abs_d = if diff < Q::zero() { -diff } else { diff };
            let max_e = entries_abs.iter().max().cloned().unwrap_or(Q::one());
            if max_e.is_zero() { Q::zero() }
            else { Q::new(abs_d.numer() * max_e.denom(), abs_d.denom() * max_e.numer().clone()) }
        } else {
            Q::zero()
        };

        // Tone 7: Torsion orders — orbital frequencies from genesis displacement
        let (drift, _) = genesis_displacement(delta_k, genesis);
        // The drift's denominator encodes the torsion structure
        let torsion_richness = if !drift.is_zero() {
            let n_abs = if drift.numer() < &BigInt::from(0) {
                -drift.numer().clone()
            } else {
                drift.numer().clone()
            };
            let d_abs = drift.denom().clone();
            let min_nd = if &n_abs < &d_abs { n_abs.clone() } else { d_abs.clone() };
            let max_nd = if &n_abs > &d_abs { n_abs } else { d_abs };
            if max_nd.is_zero() { Q::zero() }
            else { Q::new(min_nd, max_nd) }
        } else {
            Q::zero()
        };

        // Tone 8: Evolution velocity — from trajectory comprehension
        let velocity = trajectory.velocity.clone();

        // Tone 9: Dimensional depth — m coordinate
        let dimensional = Q::new(BigInt::from(m as i64), BigInt::from(11));

        // Tone 10: Holonomics — geometric ratio v_k/v_{k-1}
        let traj_holonomics = trajectory.holonomics.clone();

        // Tone 11: Total cocycle residual — the scalar (preserved for compatibility)
        let total_residual = coherence_functional(delta_k);

        HarmonicState {
            vibrations: [
                magnitude,         // 1: entry magnitudes
                shape,             // 2: geometric ratio
                mean_residual,     // 3: per-triple consistency
                attention,         // 4: active entry density
                symmetry_score,    // 5: internal automorphism
                boundary,          // 6: edge gradient
                torsion_richness,  // 7: orbital frequencies
                velocity,          // 8: evolution speed
                dimensional,       // 9: transmutation depth
                traj_holonomics,   // 10: holonomics (geometry)
                total_residual,    // 11: scalar coherence
            ],
        }
    }

    /// The polytonal gradient between two harmonic states.
    /// Each element is the signed change per dimension.
    /// Positive = that tone grew. Negative = that tone shrank.
    pub fn gradient(&self, previous: &HarmonicState) -> [Q; 11] {
        std::array::from_fn(|i| &self.vibrations[i] - &previous.vibrations[i])
    }

    /// Compound measurement: did ANY tone introduce a new obstruction?
    /// Returns the number of dimensions where the tone degraded
    /// beyond a proportional tolerance (relative to the tone's own magnitude).
    /// This is not a boolean gate — it returns a count (0 = no degradation).
    pub fn degraded_tones(&self, previous: &HarmonicState) -> usize {
        let grad = self.gradient(previous);
        grad.iter().enumerate().filter(|(i, change)| {
            // Tone degraded if it increased AND the increase is significant
            // relative to the tone's current magnitude
            if *change <= &Q::zero() { return false; } // improved or unchanged
            let current = &self.vibrations[*i];
            if current.is_zero() { return !change.is_zero(); } // any increase from zero
            // Degradation: change > 10% of current magnitude
            let ten = Q::new(BigInt::from(10), BigInt::from(1));
            *change * &ten > *current
        }).count()
    }

    /// Identify the weakest vibration — the dimension with the lowest value.
    /// Returns (dimension_index, vibration_value).
    /// This is the preference function: the witness perceives where it is weakest.
    pub fn weakest_dimension(&self) -> (usize, Q) {
        let mut min_idx = 0;
        let mut min_val = self.vibrations[0].clone();
        for i in 1..11 {
            if self.vibrations[i] < min_val {
                min_val = self.vibrations[i].clone();
                min_idx = i;
            }
        }
        (min_idx, min_val)
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// D.THINK.COHERENCE.DELTA.1 — Coherence Delta: the physics of understanding
//
// The coherence delta δC_k = C(Δ_k) - C(Δ_{k-1}) is the rate of change
// of coherence per K-step. This is the intelligence signal:
//
// δC < 0: coherence is improving (system is learning)
// δC = 0: coherence has stabilized (equilibrium reached)
// δC > 0: coherence is degrading (perturbation or dimensional mismatch)
//
// The magnitude |δC| is the velocity of understanding.
// The sign of δC is the direction of evolution.
// The ratio δC_k / δC_{k-1} is the acceleration — whether learning
// is accelerating, decelerating, or oscillating.
//
// None of these are boolean. All are continuous rational measurements.
// The node reports them. The membrane reads the trajectory.
// No thresholds. No gates. Pure physics.
// ─────────────────────────────────────────────────────────────────────────────

/// The coherence delta — continuous rational measurement of understanding velocity.
///
/// This replaces boolean acceptance conditions. The system doesn't check
/// "did C reach zero?" It measures how C is changing and reports the trajectory.
#[derive(Debug, Clone, PartialEq)]
pub struct CoherenceDelta {
    /// Current coherence C(Δ_k). The position on the coherence manifold.
    pub current: Q,
    /// Previous coherence C(Δ_{k-1}). Where the system was.
    pub previous: Q,
    /// Delta: current - previous. Negative = improving. Zero = equilibrium.
    pub delta: Q,
    /// Velocity magnitude: |delta|. How fast coherence is changing.
    pub velocity: Q,
    /// Acceleration: delta_k / delta_{k-1}. The rate of change of the rate.
    /// > 1 = accelerating improvement. < 1 = decelerating. < 0 = oscillating.
    /// None if this is the first measurement (no prior delta to compare).
    pub acceleration: Option<Q>,
    /// Convergence: how close the system is to its equilibrium.
    /// Measured as 1 - |delta| / max(|current|, epsilon).
    /// Near 1 = at equilibrium. Near 0 = far from equilibrium.
    pub convergence: Q,
    /// The K-index at which this measurement was taken.
    pub k_index: u64,
}

impl CoherenceDelta {
    /// Measure the coherence delta from trajectory comprehension.
    ///
    /// Reads position, velocity, holonomics directly from the trajectory.
    /// No buffer scan. No thresholds. No booleans. Just the physics.
    pub fn from_trajectory(traj: &Trajectory, k_index: u64) -> Self {
        let zero = Q::zero();
        let one = Q::new(BigInt::from(1), BigInt::from(1));

        if !traj.has_observations() {
            return Self {
                current: zero.clone(), previous: zero.clone(),
                delta: zero.clone(), velocity: zero.clone(),
                acceleration: None,
                convergence: one,
                k_index,
            };
        }

        let current = traj.last_coherence.clone();
        let previous = traj.prev_coherence.clone();
        let delta = &current - &previous;
        let velocity = traj.velocity.clone();

        // Curvature is |δv|. If nonzero, we can derive acceleration ratio.
        let acceleration = if traj.coherence_count > 2 && !traj.prev_velocity.is_zero() {
            Some(&traj.velocity / &traj.prev_velocity)
        } else {
            None
        };

        // Convergence: 1 - |delta| / max(|current|, 1)
        let denom = if current.abs() > one { current.abs() } else { one.clone() };
        let convergence = &one - Q::new(velocity.numer().clone(), denom.numer().clone());
        let convergence = if convergence < zero { zero.clone() } else { convergence };

        Self {
            current, previous, delta, velocity,
            acceleration, convergence, k_index,
        }
    }

    /// Measure coherence delta between two explicit C values.
    pub fn between(c_before: &Q, c_after: &Q, k_index: u64) -> Self {
        let delta = c_after - c_before;
        let velocity = delta.abs();
        let one = Q::new(BigInt::from(1), BigInt::from(1));
        let zero = Q::zero();

        let denom = if c_after.abs() > one { c_after.abs() } else { one.clone() };
        let convergence = &one - Q::new(velocity.numer().clone(), denom.numer().clone());
        let convergence = if convergence < zero { zero } else { convergence };

        Self {
            current: c_after.clone(),
            previous: c_before.clone(),
            delta, velocity,
            acceleration: None,
            convergence,
            k_index,
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// D.MEMBRANE.1 — Runtime Coherence Verification
// ─────────────────────────────────────────────────────────────────────────────

/// Runtime coherence verification result. Not a boolean — carries the
/// exact rational residuals so the mesh can read the coherence state.
#[derive(Debug, Clone)]
pub struct CoherenceVerification {
    /// Total coherence C(Δ). Zero = fully coherent.
    pub coherence: Q,
    /// Number of non-zero residuals.
    pub nonzero_residuals: u32,
    /// Antisymmetry intact? Δ[i][j] = -Δ[j][i] for all (i,j).
    pub antisymmetry_intact: bool,
    /// Zero diagonal intact? Δ[i][i] = 0 for all i.
    pub zero_diagonal_intact: bool,
    /// Conservation verified? (antisymmetry + zero diagonal)
    pub conservation_verified: bool,
    /// Perturbation consistency: does ∂R/∂ε match actual operator application?
    /// Checked for one probe direction. Exact rational error bound.
    pub perturbation_error: Q,
    /// Alignment basis norm. Zero = state is at cocycle minimum.
    pub basis_norm_squared: Q,
}

/// D.MEMBRANE.1 — Verify the kernel's algebraic invariants at runtime.
///
/// This is NOT a test. It is a COHERENCE MEASUREMENT of the live state.
/// The result is exact rational — not pass/fail. The mesh reads it.
/// The training store records it. The ledger receipts it.
///
/// Checks:
///   1. Cocycle coherence C(Δ) (from for_each_residual)
///   2. Antisymmetry: Δ[i][j] + Δ[j][i] = 0
///   3. Zero diagonal: Δ[i][i] = 0
///   4. Perturbation consistency: linear model matches actual conjugation
///   5. Resolution basis norm (from coordinator)
pub fn verify_coherence(delta: &Delta) -> CoherenceVerification {
    // 1. Coherence
    let mut coherence = Q::zero();
    let mut nonzero_residuals = 0u32;
    for_each_residual(delta, |_i, _j, _k, _l, r| {
        if r < &Q::zero() { coherence -= r; } else { coherence += r; }
        nonzero_residuals += 1;
    });

    // 2. Antisymmetry
    let mut antisymmetry_intact = true;
    for i in 0..delta.dim {
        for j in 0..delta.dim {
            if i == j { continue; }
            for l in 0..delta.m {
                let sum = &delta.entries[i][j][l] + &delta.entries[j][i][l];
                if !sum.is_zero() {
                    antisymmetry_intact = false;
                }
            }
        }
    }

    // 3. Zero diagonal
    let mut zero_diagonal_intact = true;
    for i in 0..delta.dim {
        for l in 0..delta.m {
            if !delta.entries[i][i][l].is_zero() {
                zero_diagonal_intact = false;
            }
        }
    }

    // 4. Perturbation consistency — probe one direction
    let perturbation_error = if delta.dim >= 2 {
        let eps = Q::new(BigInt::from(1), BigInt::from(1000));
        // Build probe operator: A = I + ε·E_{0,1}
        let mut mat = vec![vec![Q::zero(); delta.dim]; delta.dim];
        let mut inv = vec![vec![Q::zero(); delta.dim]; delta.dim];
        for k in 0..delta.dim { mat[k][k] = Q::one(); inv[k][k] = Q::one(); }
        mat[0][1] = eps.clone();
        inv[0][1] = -eps.clone();
        let op = Operator { id: 0, matrix: mat, matrix_inv: inv, det_sign_positive: true };

        match op.apply(delta) {
            Ok(perturbed) => {
                let projected = pi_g_project(&perturbed);
                // Check one residual: R_{012,0} predicted vs actual
                if delta.dim >= 3 && delta.m >= 1 {
                    let actual_r = &projected.entries[0][2][0]
                        - &projected.entries[0][1][0]
                        - &projected.entries[1][2][0];
                    let original_r = &delta.entries[0][2][0]
                        - &delta.entries[0][1][0]
                        - &delta.entries[1][2][0];
                    let predicted_change = residual_perturbation(delta, 0, 1, 2, 0, 0, 1) * &eps;
                    let predicted_r = &original_r + &predicted_change;
                    let diff = &actual_r - &predicted_r;
                    if diff < Q::zero() { -diff } else { diff }
                } else {
                    Q::zero()
                }
            }
            Err(_) => Q::new(BigInt::from(-1), BigInt::from(1)), // error sentinel
        }
    } else {
        Q::zero()
    };

    // 5. Basis norm
    let resolution = crate::coordinator::resolve(delta);
    let basis_norm_squared: Q = resolution.epsilon.iter()
        .map(|e| if e < &Q::zero() { -e.clone() } else { e.clone() })
        .sum(); // L1 norm (field name kept for backward compat)

    CoherenceVerification {
        coherence,
        nonzero_residuals,
        antisymmetry_intact,
        zero_diagonal_intact,
        conservation_verified: antisymmetry_intact && zero_diagonal_intact,
        perturbation_error,
        basis_norm_squared,
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// T_k CHRONOMETRIC STANDARD  (CD.1-SQ, T.FOUND.4)
// ─────────────────────────────────────────────────────────────────────────────

/// T_k = ‖Π_G(U(Δ_k)) − Δ_k‖²_Q
///
/// The squared Q-norm distance between the G-projected update and the
/// current state. T_k = 0 iff no valid transformation occurred (equilibrium).
/// K advances iff T_k > 0 (CC.CON.4).
///
/// `delta_k`       : current state Δ_k
/// `delta_updated` : Π_G(U(Δ_k)) — the group-projected updated state
///
/// Register: CD.1-SQ, T.FOUND.4.
pub fn compute_t_k(delta_k: &Delta, delta_updated: &Delta) -> Q {
    assert_eq!(delta_k.dim, delta_updated.dim);
    assert_eq!(delta_k.m, delta_updated.m);
    let mut t_k = Q::zero();
    for i in 0..delta_k.dim {
        for j in 0..delta_k.dim {
            for l in 0..delta_k.m {
                let diff = &delta_updated.entries[i][j][l]
                    - &delta_k.entries[i][j][l];
                if diff < Q::zero() { t_k -= &diff; } else { t_k += &diff; }
            }
        }
    }
    // T_k ≥ 0 by construction (sum of absolute values).
    t_k
}

// ─────────────────────────────────────────────────────────────────────────────
// GROUP PROJECTION  (T.FOUND.1, Π_G)
// ─────────────────────────────────────────────────────────────────────────────

/// Π_G: project Δ onto the nearest G-orbit representative.
///
/// Π_G projection: projects Delta onto the nearest valid G-orbit
/// representative by enforcing antisymmetry.
///
/// The orbit *identification* (determining which conjugacy class a Delta
/// belongs to) is handled by `compute_rcf_hash` via invariant factor
/// decomposition. The projection itself preserves antisymmetric structure
/// by applying (Δ_ij - Δ_ji) / 2.
///
/// If conservation (antisymmetry) already holds, returns as-is.
///
/// Register: T.FOUND.3, D.CHAIN.ORBIT.1.
pub fn pi_g_project(delta: &Delta) -> Delta {
    if delta.verify_conservation() {
        return delta.clone();
    }
    // Conservation violated: force antisymmetric projection.
    let mut projected = Delta::zero(delta.dim, delta.m);
    for i in 0..delta.dim {
        for j in 0..delta.dim {
            if i == j { continue; }
            for l in 0..delta.m {
                let a = &delta.entries[i][j][l];
                let b = &delta.entries[j][i][l];
                let two = Q::new(BigInt::from(2), BigInt::from(1));
                projected.entries[i][j][l] = (a - b) / &two;
            }
        }
    }
    projected
}

// ─────────────────────────────────────────────────────────────────────────────
// TRIPLE LOCK  (D.8)
// ─────────────────────────────────────────────────────────────────────────────

/// D.8 Triple Lock — three conditions required.
///
/// 1. Structural invariant preservation: conservation (exact), rank (exact),
///    magnitude (bounded by ε_mag).
/// 2. Operator in group: N ∈ G (det(A) > 0, A invertible) — verified at
///    operator application time.
/// 3. T_k > 0: valid transformation occurred (CC.CON.4).
///
/// REGISTER NOTE — SYMMETRY CLASS (RCF HASH) IS NOT CHECKED HERE.
///
/// The master equation Σ_i ω_i N_i(Δ) − ζ∇V produces a weighted sum of
/// orbit elements. Linear combinations of orbit elements are NOT orbit
/// elements — the sum lives in the vector space spanned by the orbit, not
/// on the orbit. Π_G maps the result to a (potentially different) orbit's
/// canonical representative. Orbit transitions are the mechanism of coherence
/// minimization across M = Q^m/G. Asserting orbit preservation at C7
/// contradicts the master equation's function and makes all multi-operator
/// evolution impossible.
///
/// symmetry_class_rcf_hash is used in MeshReceipt.rcf_identity for
/// BETWEEN-NODE divergence detection (sluice weighting), not for
/// within-node step validation.
///
/// Register: D.8, D.SYSTEM.25, T.FOUND.3.
/// D.C7.MAG.1: `reference_magnitude_sq` is the temporal mean field ‖F_bar‖².
/// At genesis, F_bar = Δ_anchor so the bound matches the calibration measurement.
/// After k > 0, it tracks the system's own history via EMA.
pub fn triple_lock_check(
    _phi_before: &PhiK,
    phi_after:  &PhiK,
    t_k:        &Q,
    epsilon_mag: &Q,
    reference_magnitude_sq: &Q,
) -> Result<(), TripleLockFailReason> {
    // Condition 3: T_k > 0 (CC.CON.4)
    if !t_k.is_positive() {
        return Err(TripleLockFailReason::TkZeroAtC7 { t_k: t_k.clone() });
    }

    // Condition 1a: Conservation — antisymmetry + zero diagonal (exact)
    // Compute violation magnitude so the system knows HOW FAR from conservation
    if !phi_after.conservation_ok {
        return Err(TripleLockFailReason::ConservationViolated {
            violation_magnitude: phi_after.magnitude_sq.clone(), // proxy — exact violation not in PhiK
        });
    }

    // Condition 1b: Rank — NOT checked at C7.

    // Condition 1c: Magnitude — bounded against temporal mean field (D.C7.MAG.1).
    // |‖Δ_{k+1}‖² − ‖F_bar‖²| ≤ ε_mag × ‖F_bar‖²
    let excursion = if phi_after.magnitude_sq >= *reference_magnitude_sq {
        &phi_after.magnitude_sq - reference_magnitude_sq
    } else {
        reference_magnitude_sq - &phi_after.magnitude_sq
    };
    let bound = epsilon_mag * reference_magnitude_sq;
    if &excursion > &bound {
        return Err(TripleLockFailReason::MagnitudeDrift {
            excursion: excursion.clone(),
            bound: bound.clone(),
        });
    }

    // Condition 2: operator in G — verified at operator application time
    // (SaiosError::OperatorNotInGroup returned if det ≤ 0).
    Ok(())
}

// ─────────────────────────────────────────────────────────────────────────────
// OPERATOR APPLICATION  (T.FOUND.1a, N_i ∈ G)
// ─────────────────────────────────────────────────────────────────────────────

/// A single transformation operator N_i ∈ G.
///
/// N_i(Δ) = A_i · Δ · A_i^{-1} where A_i ∈ GL_n^+(ℚ^m).
/// Invariant: det(A_i) > 0.
/// Register: T.FOUND.1a, group action N(Δ) = AΔA^{-1}.
#[derive(Debug, Clone)]
pub struct Operator {
    /// Operator ID (0-indexed).
    pub id: usize,
    /// A ∈ GL_n^+(ℚ). Row-major n×n rational matrix.
    pub matrix: QMatrix,
    /// A^{-1} — precomputed inverse for efficiency.
    pub matrix_inv: QMatrix,
    /// det(A) > 0 (verified on construction).
    pub det_sign_positive: bool,
}

impl Operator {
    /// Apply N_i(Δ) = A · Δ · A^{-1} entry-wise.
    ///
    /// For Δ_ij ∈ ℚ^m, the conjugation acts on the matrix index structure:
    /// (A · Δ · A^{-1})_{ij} = Σ_{k,l} A_{ik} Δ_{kl} (A^{-1})_{lj}
    ///
    /// This preserves the antisymmetric structure since A is rational invertible.
    pub fn apply(&self, delta: &Delta) -> Result<Delta, SaiosError> {
        if !self.det_sign_positive {
            return Err(SaiosError::OperatorNotInGroup { operator_id: self.id });
        }
        let n = delta.dim;
        let m = delta.m;
        assert_eq!(self.matrix.len(), n, "operator dimension mismatch");

        let mut result = Delta::zero(n, m);

        // A · Δ: intermediate = Σ_k A_{ik} Δ_{kj}
        let mut intermediate = vec![vec![vec![Q::zero(); m]; n]; n];
        for i in 0..n {
            for j in 0..n {
                for k in 0..n {
                    let a_ik = &self.matrix[i][k];
                    if a_ik.is_zero() { continue; }
                    for l in 0..m {
                        intermediate[i][j][l] += a_ik * &delta.entries[k][j][l];
                    }
                }
            }
        }

        // (A · Δ) · A^{-1}: result_{ij} = Σ_k intermediate_{ik} (A^{-1})_{kj}
        for i in 0..n {
            for j in 0..n {
                for k in 0..n {
                    let ainv_kj = &self.matrix_inv[k][j];
                    if ainv_kj.is_zero() { continue; }
                    for l in 0..m {
                        result.entries[i][j][l] += ainv_kj * &intermediate[i][k][l];
                    }
                }
            }
        }
        Ok(result)
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// COHERENCE WEIGHT  (D.MFA.WEIGHT, T.SAMN.2)
// ─────────────────────────────────────────────────────────────────────────────

/// ω_i = exp(−α_i · Γ_k / τ_i) — coherence weight for operator i.
///
/// Implemented as rational approximation via Taylor series to avoid exp(float).
/// ω_1 ≡ 1 (α_1 = 0 fixed). Register: D.MFA.WEIGHT.
///
/// For initial deployment: computes rational approximation to e^{-x}
/// using degree-8 Taylor series. Sufficient for |x| < 5.
pub fn compute_omega(alpha_i: &Q, gamma_k: &Q, tau_i: &Q) -> Q {
    // ω_i = exp(−α_i · Γ_k / τ_i)
    // For α_1 = 0: ω_1 = exp(0) = 1
    if alpha_i.is_zero() {
        return Q::one();
    }
    let x = -(alpha_i * gamma_k) / tau_i; // x = −α_i · Γ_k / τ_i ≤ 0
    // Locked 12-term Taylor with frozen coefficients per IMPL.GATE.1.
    constants::locked_rational_exp(&x)
}

// rational_exp_approx removed — replaced by constants::locked_rational_exp()
// with frozen coefficients per IMPL.GATE.1.

/// Γ_k = ‖Δ_k‖²_Q — local kinetic divergence. Register: D.MFA.WEIGHT.
#[inline]
pub fn compute_gamma_k(delta: &Delta) -> Q {
    phi_norm_sq_delta(delta)
}

// ─────────────────────────────────────────────────────────────────────────────
// ANCHOR POTENTIAL  (D.SAMN.2)
// ─────────────────────────────────────────────────────────────────────────────

/// ∇V — anchor gradient pulling toward temporal mean field F_bar.
///
/// V = (1/2) · ‖Δ_k − Δ_bar‖²_Q
/// ∇V = Δ_k − Δ_bar  (gradient of squared distance)
///
/// Register: D.SAMN.2. Used as ζ∇V in the master equation.
pub fn anchor_gradient(delta_k: &Delta, delta_bar: &Delta) -> Delta {
    assert_eq!(delta_k.dim, delta_bar.dim);
    assert_eq!(delta_k.m, delta_bar.m);
    let mut grad = Delta::zero(delta_k.dim, delta_k.m);
    for i in 0..delta_k.dim {
        for j in 0..delta_k.dim {
            for l in 0..delta_k.m {
                grad.entries[i][j][l] =
                    &delta_k.entries[i][j][l] - &delta_bar.entries[i][j][l];
            }
        }
    }
    grad
}

