/// Trajectory comprehension: the witness's understanding of its own motion.
///
/// Three measurements — position, velocity, holonomics — computed incrementally.
/// No buffer. No cap. No discarding. The witness comprehends its trajectory
/// rather than remembering raw history.
#[derive(Debug, Clone)]
pub struct Trajectory {
    /// Current coherence C(Δ_k). Position on the coherence manifold.
    pub last_coherence: Q,
    /// |δC| — how fast coherence is changing. The velocity of understanding.
    pub velocity: Q,
    /// v_k / v_{k-1} — geometric ratio of consecutive velocities. Holonomics.
    /// = 1: constant motion. < 1: converging. > 1: diverging. Proportion, not derivative.
    pub holonomics: Q,
    /// Previous coherence — internal state for next velocity computation.
    pub prev_coherence: Q,
    /// Previous velocity — internal state for next holonomics computation.
    pub prev_velocity: Q,
    /// Running maximum coherence observed (for MDC legal envelope).
    pub max_coherence: Q,
    /// Running sum of all coherence values (for sigma_enc mean).
    pub coherence_sum: Q,
    /// Count of all K-steps observed (for sigma_enc mean).
    pub coherence_count: u32,
}

impl Trajectory {
    /// Empty trajectory — no observations yet.
    pub fn new() -> Self {
        Trajectory {
            last_coherence: Q::zero(),
            velocity: Q::zero(),
            holonomics: Q::zero(),
            prev_coherence: Q::zero(),
            prev_velocity: Q::zero(),
            max_coherence: Q::zero(),
            coherence_sum: Q::zero(),
            coherence_count: 0,
        }
    }

    /// Update trajectory with a new coherence measurement.
    /// Computes velocity and shape incrementally.
    pub fn observe(&mut self, coherence: Q) {
        self.prev_coherence = self.last_coherence.clone();
        self.prev_velocity = self.velocity.clone();

        // Velocity: |C_k - C_{k-1}| (algebra — relationship between two values)
        if self.coherence_count > 0 {
            let diff = &coherence - &self.prev_coherence;
            self.velocity = if diff < Q::zero() { -diff } else { diff };
        }

        // Holonomics: v_k / v_{k-1} (geometry — proportion, not derivative)
        // = 1: constant motion (line). < 1: converging (closing). > 1: diverging (opening).
        if self.coherence_count > 1 && !self.prev_velocity.is_zero() {
            self.holonomics = &self.velocity / &self.prev_velocity;
        }

        // Running max
        if coherence > self.max_coherence {
            self.max_coherence = coherence.clone();
        }

        // Running mean state
        self.coherence_sum = &self.coherence_sum + &coherence;
        self.coherence_count += 1;

        self.last_coherence = coherence;
    }

    /// Restore trajectory from genome values (3 measurements + max + mean state).
    pub fn from_genome(last: Q, velocity: Q, holonomics: Q, max_c: Q, sum: Q, count: u32) -> Self {
        Trajectory {
            prev_coherence: &last - if velocity >= Q::zero() { velocity.clone() } else { -velocity.clone() },
            prev_velocity: Q::zero(),
            last_coherence: last,
            velocity,
            holonomics,
            max_coherence: max_c,
            coherence_sum: sum,
            coherence_count: count,
        }
    }

    /// Whether any observations have been made.
    pub fn has_observations(&self) -> bool {
        self.coherence_count > 0
    }

    /// Mean coherence across all observations.
    pub fn mean_coherence(&self) -> Q {
        if self.coherence_count == 0 { return Q::zero(); }
        &self.coherence_sum / &Q::from_integer(BigInt::from(self.coherence_count as i64))
    }
}

/// Per-entity execution state maintained across K-steps.
///
/// Persisted to saios-db at each K-step. Used for continuity.
#[derive(Debug, Clone)]
pub struct WitnessState {
    /// Entity identifier. Max 16,777,215 (uint24). Register: CC.CHAIN.NODE.1.
    pub entity_id: u32,
    /// Current K-step index. Strictly monotone. Register: I10, D.EXEC.1.
    pub k_index: u32,
    /// Current sluice state. Register: D.SAIOS.1.
    pub sluice_state: SluiceState,
    /// Latest sigma_enc (Q0.32 fixed-point Σ_global). Register: AN.CHAIN.SIGMA.1.
    pub latest_sigma_enc: u32,
    /// Current Δ_k — the node's relational state.
    pub delta_k: Delta,
    /// Chronometry v1.0: H^1 reference = coboundary_reduce(delta_k). No EMA.
    /// The manifold position is exact. Temporal memory is in trajectory + genome.
    pub delta_bar: Delta,
    /// Trajectory comprehension — replaces coherence_history buffer.
    pub trajectory: Trajectory,
    /// Latest T_k (rational). Register: CD.1-SQ.
    pub t_k_latest: Q,
}

impl WitnessState {
    /// Compute Q0.32 fixed-point encoding of Σ_global ∈ [0,1].
    /// Register: D.CHAIN.1-ENC-v2, U.CHAIN.3.
    pub fn compute_sigma_enc(&self) -> u32 {
        if !self.trajectory.has_observations() { return 0u32; }
        let mean = self.trajectory.mean_coherence();
        // Clamp to [0, 1]
        let clamped = if mean < Q::zero() { Q::zero() }
            else if mean > Q::one() { Q::one() }
            else { mean };
        // Q0.32 encoding: round_half_even(σ · 2^32)
        let scale = Q::from_integer(BigInt::from(1u64 << 32));
        let scaled = &clamped * &scale;
        let floor_v = scaled.floor();
        let frac = &scaled - &floor_v;
        let half = Q::new(BigInt::from(1), BigInt::from(2));
        let rounded_int = if frac == half {
            let f = floor_v.to_integer();
            let is_odd = &f % BigInt::from(2) != BigInt::from(0);
            if is_odd { f + BigInt::from(1) } else { f }
        } else if frac > half {
            floor_v.to_integer() + BigInt::from(1)
        } else {
            floor_v.to_integer()
        };
        // Saturate at u32::MAX
        use num_traits::ToPrimitive;
        rounded_int.to_u32().unwrap_or(u32::MAX)
    }
}

