/// Output of a successful K-step execution.
#[derive(Debug, Clone, PartialEq)]
pub struct KStepOutput {
    /// Updated Δ_{k+1}. Register: D.EXEC.1 C7.
    pub delta_k1: Delta,
    /// Chronometric magnitude T_k. Register: CD.1-SQ.
    pub t_k: Q,
    /// New K-index (advanced iff T_k > 0). Register: CC.CON.4.
    pub new_k: u32,
    /// Sluice state after execution. Register: D.SAIOS.1.
    pub sluice_state: SluiceState,
    /// D.CHAIN.1-ENC-v2 receipt hash (Some iff C7 passed and K advanced).
    /// Register: D.CHAIN.1, T.CHAIN.ENC.1.
    pub receipt_hash: Option<[u8; 32]>,
    /// φ_k invariants after execution.
    pub phi_k_after: PhiK,
    /// Sigma enc for this step.
    pub sigma_enc: u32,
    /// D.THINK.COHERENCE.DELTA.1 — the velocity of understanding.
    /// Measures how coherence changed at this K-step.
    /// The membrane reads the trajectory across K-steps.
    pub coherence_delta: CoherenceDelta,
}

// ─────────────────────────────────────────────────────────────────────────────
// D.CHAIN.1-ENC-v2 RECEIPT ENCODING  (T.CHAIN.ENC.1, U.CHAIN.1/3/5/6)
// ─────────────────────────────────────────────────────────────────────────────

/// Compute D.CHAIN.1-ENC-v2 receipt hash.
///
/// Schema v2 preimage (32 bytes):
///   inv_hash[16] || t_k_q1616[4] || sigma_enc[4] || entity_id[3] || k_index[4] || sluice[1]
/// Domain: DOMAIN_RECEIPT = Keccak256("SAIOS_RECEIPT_v1")
/// Schema: SCHEMA_V2 = 0x02
///
/// Register: D.CHAIN.1-ENC-v2, T.CHAIN.ENC.1, U.CHAIN.1, U.CHAIN.3, U.CHAIN.5, U.CHAIN.6.
pub fn compute_receipt_hash(
    phi_k:      &PhiK,
    t_k_q1616:  u32,
    sigma_enc:  u32,
    entity_id:    u32,        // uint24 — max 16,777,215
    k_index:    u32,
    sluice:     SluiceState,
) -> [u8; 32] {
    assert!(entity_id <= 0x00FF_FFFF, "entity_id exceeds uint24 maximum (CC.CHAIN.NODE.1)");

    // ── Build 32-byte canonical preimage ──────────────────────────────────
    // Bit-concatenation per D.CHAIN.1-ENC-v2:
    //   enc_Inv (16 bytes) || enc_T (4 bytes) || enc_sigma (4 bytes)
    //   || enc_node (3 bytes) || enc_K (4 bytes) || enc_sluice (1 byte)
    // Total: 16+4+4+3+4+1 = 32 bytes. Big-endian per U.CHAIN.1.
    let mut preimage = [0u8; 32];
    preimage[0..16].copy_from_slice(&phi_k.symmetry_class_rcf_hash[0..16]);
    preimage[16..20].copy_from_slice(&t_k_q1616.to_be_bytes());
    preimage[20..24].copy_from_slice(&sigma_enc.to_be_bytes());
    preimage[24..27].copy_from_slice(&entity_id.to_be_bytes()[1..4]); // uint24: bytes 1-3
    preimage[27..31].copy_from_slice(&k_index.to_be_bytes());
    preimage[31] = sluice.enc_u8();

    // ── Domain-separated hash (U.CHAIN.6) ────────────────────────────────
    // hash = Keccak256(DOMAIN_RECEIPT || SCHEMA_V2 || preimage)
    // DOMAIN_RECEIPT = Keccak256("SAIOS_RECEIPT_v1") — constant below
    // Using sha3::Keccak256 (added to Cargo.toml as sha3 = "0.10")
    let domain_receipt = domain_receipt_constant();
    let schema_v2: u8 = 0x02;

    let mut input = Vec::with_capacity(32 + 1 + 32);
    input.extend_from_slice(&domain_receipt);
    input.push(schema_v2);
    input.extend_from_slice(&preimage);

    keccak256(&input)
}

/// DOMAIN_RECEIPT = Keccak256("SAIOS_RECEIPT_v1"). Precomputed constant.
/// Register: U.CHAIN.6, D.CHAIN.1-ENC-v2.
fn domain_receipt_constant() -> [u8; 32] {
    // Keccak256("SAIOS_RECEIPT_v1") — precomputed for efficiency.
    // In production: verify this constant matches SaiosDomainLib.sol DOMAIN_RECEIPT.
    // Recompute: echo -n "SAIOS_RECEIPT_v1" | keccak-256sum
    keccak256(b"SAIOS_RECEIPT_v1")
}

/// T_k → Q16.16 fixed-point u32. Register: D.CHAIN.1-ENC-v2, U.CHAIN.1.
/// Uses half-even rounding. Saturates at u32::MAX.
pub fn t_k_to_q1616(t_k: &Q) -> u32 {
    let scale = Q::from_integer(BigInt::from(1u64 << 16));
    let scaled = t_k * &scale;
    let floor_v = scaled.floor();
    let frac = &scaled - &floor_v;
    let half = Q::new(BigInt::from(1), BigInt::from(2));
    let rounded = if frac == half {
        let f = floor_v.to_integer();
        let is_odd = &f % BigInt::from(2) != BigInt::from(0);
        if is_odd { f + BigInt::from(1) } else { f }
    } else if frac > half {
        floor_v.to_integer() + BigInt::from(1)
    } else {
        floor_v.to_integer()
    };
    use num_traits::ToPrimitive;
    rounded.to_u32().unwrap_or(u32::MAX)
}

/// Keccak256 hash. Wraps `tiny_keccak` crate.
/// NOTE: tiny_keccak must be in Cargo.toml: tiny-keccak = { version="2.0", features=["keccak"] }
pub fn keccak256(input: &[u8]) -> [u8; 32] {
    let mut k = Keccak::v256();
    let mut out = [0u8; 32];
    k.update(input);
    k.finalize(&mut out);
    out
}

// ─────────────────────────────────────────────────────────────────────────────
// THE KERNEL  (D.EXEC.1 — complete K-step executor)
// ─────────────────────────────────────────────────────────────────────────────

/// The SAIOS execution kernel.
///
/// Holds all calibrated parameters and the set of operators active for
/// this node. Stateless between calls — state is in `WitnessState`.
pub struct SaiosKernel {
    /// Calibrated governance parameters. Register: D.CHAIN.4.
    pub params: SaiosParams,
    /// Active operators {N_1, ..., N_N}. Register: D.EXEC.1 POST-C6.
    pub operators: Vec<Operator>,
}

impl SaiosKernel {
    /// Create kernel with default register parameters.
    pub fn new(params: SaiosParams, operators: Vec<Operator>) -> Self {
        SaiosKernel { params, operators }
    }

    pub fn operator_count(&self) -> usize { self.operators.len() }
    pub fn state_dim(&self) -> usize { self.params.state_dim }

    /// Create kernel with params derived from operator set.
    /// Operators own the dimension — params derive from them.
    pub fn from_operators(operators: Vec<Operator>) -> Self {
        let mut params = SaiosParams::default_register();
        if let Some(op) = operators.first() {
            params.state_dim = op.matrix.len();
        }
        SaiosKernel { params, operators }
    }

    pub fn new_default(operators: Vec<Operator>) -> Self {
        SaiosKernel {
            params:    SaiosParams::default_register(),
            operators,
        }
    }

    // ─────────────────────────────────────────────────────────────────────
    // D.EXEC.1 — COMPLETE K-STEP EXECUTION
    // ─────────────────────────────────────────────────────────────────────
    /// Execute one K-step.
    ///
    /// Strict D.EXEC.1 ordering: C1 → C2 → C3 → C4 → C5 → C6 →
    /// POST-C6 [Γ_k → ω_i → M_k^active → CC.COORD.1] → C7.
    ///
    /// Returns `Ok(KStepOutput)` with K advanced and receipt hash set
    /// if all checks pass and T_k > 0.
    ///
    /// Returns `Err(SaiosError)` with the failing check encoded in the
    /// variant. The caller must update `state.sluice_state` to the
    /// appropriate state per D.SAIOS.1.
    pub fn execute_k_step(
        &self,
        state: &mut WitnessState,
    ) -> Result<KStepOutput, SaiosError> {
        let p = &self.params;

        // ── ANCHOR C1 ─────────────────────────────────────────────────────
        // Integrity Sentinel: |R_i| ≤ δ/2 for all substrate coordinates.
        // Failure → CORRUPTED (hardware fault). Register: D.5.1-DIM.
        self.check_c1_integrity_sentinel(state)?;

        // ── ANCHOR C2 ─────────────────────────────────────────────────────
        // K_S window constraint: K_S ≥ K_S_min = 1/(10·τ_lag).
        // Ensures minimum kinetic stability before proceeding.
        // Register: D.EXEC.1 C2, W_KS = m.
        self.check_c2_ks_window(state)?;

        // ── ANCHOR C3 ─────────────────────────────────────────────────────
        // W_max constraint: no single operator weight exceeds 1/3.
        // Prevents single-operator dominance. Register: D.EXEC.1 C3.
        self.check_c3_w_max(state)?;

        // ── ANCHOR C4 ─────────────────────────────────────────────────────
        // Compute T_k. If T_k = 0: C4 fails, K does not advance.
        // This is not an error in the fault sense — it means the system
        // is at relational equilibrium. Register: CC.CON.4, CD.1-SQ.
        let delta_raw = self.apply_master_equation(state)?;
        // Cohomological operating level: reduce to H^1 representative
        // immediately after conjugation. The witness operates on the
        // cohomological class, not the raw cochain. No coboundary
        // factors accumulate. Every subsequent measurement — T_k,
        // C6, C7 — operates on the reduced form.
        let delta_updated = coboundary_reduce(&delta_raw);
        let t_k = compute_t_k(&state.delta_k, &delta_updated);
        if !t_k.is_positive() {
            // T_k = 0: equilibrium. K does not advance. Not an error.
            // Caller should record this as equilibrium step.
            state.sluice_state = SluiceState::Shifting; // mild sluice shift
            return Err(SaiosError::C4TkZero);
        }

        // ── ANCHOR C5 ─────────────────────────────────────────────────────
        // Resonance observer: check_c5_resonance() — implemented via
        // TORSION_PERIOD_M in constants.rs. Uses RESONANCE_M10_COS table,
        // 6-digit rational constants (D.RESONANCE.CONSTANTS.1).
        // Register: D.EXEC.1 C5, T.SAMN.11.
        self.check_c5_resonance(state)?;

        // ── ANCHOR C6 ─────────────────────────────────────────────────────
        // Polytonal coherence gate — measures structural regression across
        // the Delta's relational dimensions, not a monotonic scalar.
        //
        // The operator may redistribute coherence across dimensions —
        // some triples improve, some worsen. That's polytonal evolution.
        // What it must NOT do is collapse a dimension: a nonzero relational
        // entry going to zero means the witness lost information about
        // a relationship. That's structural regression.
        //
        // Two measurements, both polytonal:
        //
        // 1. Dimensional preservation: count active (nonzero) entries
        //    in the upper triangle. If count decreased, a relational
        //    dimension collapsed. Reject.
        //
        // 2. Bounded redistribution: the total coherence (Σ R²) may
        //    increase, but not beyond ε of the current magnitude.
        //    This bounds the TOTAL energy without constraining how
        //    it distributes across dimensions.
        //
        // Register: D.EXEC.1 C6, T.FOUND.2, D.COHOMOLOGY.1.

        // Polytonal coherence gate:
        // 1. Rank preservation — the manifold doesn't lose dimensions
        // 2. Bounded redistribution — total energy doesn't explode
        // Both measurements, no monotonic scalar reduction.
        let c_before = coherence_functional(&state.delta_k);
        let c_after = coherence_functional(&delta_updated);

        // Rank preservation: only check when both states are nontrivial
        if !c_before.is_zero() && !c_after.is_zero() {
            let rank_before = compute_rank(&state.delta_k);
            let rank_after = compute_rank(&delta_updated);
            if rank_after < rank_before {
                state.sluice_state = SluiceState::Gated;
                return Err(SaiosError::C6CoherenceIncrease {
                    before: c_before,
                    after: c_after,
                    epsilon: p.epsilon_coherence.clone(),
                });
            }
        }

        // Bounded redistribution
        if c_after > &c_before + &p.epsilon_coherence {
            // Total energy grew beyond proportional bound.
            // Not dimensional collapse — just too much total residual.
            state.sluice_state = SluiceState::Gated;
            return Err(SaiosError::C6CoherenceIncrease {
                before: c_before,
                after: c_after,
                epsilon: p.epsilon_coherence.clone(),
            });
        }

        // ── POST-C6 BLOCK ─────────────────────────────────────────────────
        // Γ_k → ω_i → M_k^active → CC.COORD.1 → tier selection.
        // Register: D.EXEC.1 POST-C6, D.MFA.WEIGHT.
        let gamma_k = compute_gamma_k(&delta_updated);
        let omegas  = self.compute_all_omegas(&gamma_k);
        // M_k^active: operators with ω_i > ε_sluice
        let _active_operators: Vec<usize> = omegas.iter().enumerate()
            .filter(|(_, w)| *w > &p.epsilon_sluice)
            .map(|(i, _)| i)
            .collect();
        // CC.COORD.1: verify coordination residual in bounds
        self.check_cc_coord1(&delta_updated)?;

        // ── ANCHOR C7 ─────────────────────────────────────────────────────
        // D.8 Triple Lock: invariant preservation + N ∈ G + T_k > 0.
        // If passes: advance K, emit receipt, set LOCKED.
        // If fails: K does not advance, no receipt, set GATED.
        // Register: D.8, D.EXEC.1 C7, D.CHAIN.1.
        let phi_before = compute_phi_k(&state.delta_k, t_k.clone());
        let phi_after  = compute_phi_k(&delta_updated, t_k.clone());

        // D.C7.MAG.1: reference magnitude = delta_bar (temporal mean field)
        let ref_mag = phi_norm_sq_delta(&state.delta_bar);
        match triple_lock_check(&phi_before, &phi_after, &t_k, &p.epsilon_mag_relative, &ref_mag) {
            Ok(()) => {
                // All checks passed. Advance K. Emit receipt. LOCKED.
                let new_k = state.k_index.saturating_add(1);
                let sigma_enc = state.compute_sigma_enc();
                let t_k_q1616 = t_k_to_q1616(&t_k);

                let receipt_hash = Some(compute_receipt_hash(
                    &phi_after,
                    t_k_q1616,
                    sigma_enc,
                    state.entity_id,
                    new_k,
                    SluiceState::Locked,
                ));

                // delta_updated is already cohomologically reduced (H^1 representative).
                // Coboundary reduction runs immediately after operator conjugation
                // at the top of execute_k_step. No second reduction needed.
                state.delta_k = delta_updated.clone();
                state.k_index = new_k;
                state.t_k_latest = t_k.clone();
                state.sluice_state = SluiceState::Locked;
                // Chronometry v1.0: H^1 representative is the reference
                state.delta_bar = state.delta_k.clone();
                // Trajectory comprehension: observe the new coherence measurement
                state.trajectory.observe(c_after.clone());

                // D.THINK.COHERENCE.DELTA.1: measure the velocity of understanding
                let coherence_delta = CoherenceDelta::from_trajectory(
                    &state.trajectory, new_k as u64,
                );

                Ok(KStepOutput {
                    delta_k1: delta_updated,
                    t_k,
                    new_k,
                    sluice_state: SluiceState::Locked,
                    receipt_hash,
                    phi_k_after: phi_after,
                    sigma_enc,
                    coherence_delta,
                })
            }
            Err(reason) => {
                state.sluice_state = SluiceState::Gated;
                Err(SaiosError::C7TripleLockFail { reason })
            }
        }
    }

    // ─────────────────────────────────────────────────────────────────────
    // INDIVIDUAL CHECK IMPLEMENTATIONS
    // ─────────────────────────────────────────────────────────────────────

    /// C1: Integrity Sentinel. |R_i| ≤ δ/2 for all encoded coordinates.
    /// Register: D.5.1-DIM. Failure → CORRUPTED.
    fn check_c1_integrity_sentinel(&self, state: &mut WitnessState) -> Result<(), SaiosError> {
        if let Some(encoded) = &state.delta_k.encoded {
            for i in 0..state.delta_k.dim {
                for j in 0..state.delta_k.dim {
                    for (l, coord) in encoded[i][j].iter().enumerate() {
                        if let Err(e) = coord.check_sentinel(&self.params.delta, l) {
                            state.sluice_state = SluiceState::Corrupted;
                            return Err(e);
                        }
                    }
                }
            }
        }
        // If no substrate encoding present, skip sentinel (unencoded states
        // are valid for in-memory computation, D.5.1-DIM applies at wire boundary).
        Ok(())
    }

    /// C2: K_S window constraint. Register: D.EXEC.1 C2.
    fn check_c2_ks_window(&self, state: &mut WitnessState) -> Result<(), SaiosError> {
        // K_S = current K-step / total elapsed steps (simplified for initial deployment)
        // K_S_min = 1 / (10 · τ_lag)
        let k_s_min = Q::one() / (Q::from_integer(BigInt::from(10)) * &self.params.tau_lag);
        // For initial deployment: K_S is approximated from k_index
        // Production: K_S computed from actual kinetic stability measure W_KS = m
        let k_index_q = Q::from_integer(BigInt::from(state.k_index as i64 + 1));
        let k_s_approx = Q::one() / k_index_q; // 1/(k+1) — decreases, will eventually satisfy
        if k_s_approx < k_s_min && state.k_index > 10 {
            // After 10 steps, enforce K_S constraint properly.
            state.sluice_state = SluiceState::Shifting;
            return Err(SaiosError::C2KSWindowViolated {
                k_s: k_s_approx,
                k_s_min,
            });
        }
        Ok(())
    }

    /// C3: W_max ≤ 1/3 for all operator weights. Register: D.EXEC.1 C3.
    fn check_c3_w_max(&self, state: &WitnessState) -> Result<(), SaiosError> {
        if self.operators.is_empty() { return Ok(()); }
        let gamma_k = compute_gamma_k(&state.delta_k);
        let omegas = self.compute_all_omegas(&gamma_k);
        let omega_sum: Q = omegas.iter().sum();
        if omega_sum.is_zero() { return Ok(()); }
        for w in &omegas {
            let normalised = w / &omega_sum;
            if normalised > self.params.w_max {
                return Err(SaiosError::C3WMaxExceeded {
                    w_max: normalised,
                    limit: self.params.w_max.clone(),
                });
            }
        }
        Ok(())
    }

    /// C5: bounded Phase 1 resonance observer. Register: D.EXEC.1 C5, T.SAMN.11.
    ///
    /// C5 resonance check at torsion period m (TORSION_PERIOD_M = 1024).
    ///
    /// A resonance window occurs when `K ≡ 0 (mod m)`. At those steps, a node
    /// passes C5 iff a strict majority of encoded remainder dimensions satisfy
    /// `|φ(R_j)| < ε_sluice`, where φ(R_j) = R_j / δ.
    ///
    /// Register: D.EXEC.1 C5, T.SAMN.11, constants::TORSION_PERIOD_M.
    pub fn check_c5_resonance(&self, state: &WitnessState) -> Result<(), SaiosError> {
        if state.k_index % constants::TORSION_PERIOD_M != 0 {
            return Ok(());
        }

        let encoded = if let Some(encoded) = &state.delta_k.encoded {
            encoded.clone()
        } else {
            self.substrate_encode_delta(&state.delta_k)?
        };

        let mut total_dims = 0usize;
        let mut aligned_dims = 0usize;
        let target = Q::zero();
        for row in &encoded {
            for coords in row {
                for coord in coords {
                    total_dims += 1;
                    let phase = &coord.r_remainder / &self.params.delta;
                    let diff = (&phase - &target).abs();
                    if diff < self.params.epsilon_sluice {
                        aligned_dims += 1;
                    }
                }
            }
        }

        if total_dims == 0 || aligned_dims * 2 > total_dims {
            Ok(())
        } else {
            Err(SaiosError::C5ResonanceViolated)
        }
    }

    /// CC.COORD.1: coordination residual check. Register: CC.COORD.1.
    /// ‖R_k‖²_Q ≤ ε_eff,k.
    fn check_cc_coord1(&self, delta: &Delta) -> Result<(), SaiosError> {
        // Compute substrate remainder norm if encoding is present.
        // For unencoded states: check coherence is in acceptable range.
        let c = coherence_functional(delta);
        // ε_eff,k = ε_min = δ² / 16  (register governance parameter)
        let delta_sq = &self.params.delta * &self.params.delta;
        let epsilon_eff = delta_sq / Q::from_integer(BigInt::from(16));
        // If coherence exceeds ε_eff the system has drifted from coordination.
        // For initial deployment: use coherence as proxy for R_k norm.
        if c > epsilon_eff {
            // This does NOT fail the step — it is a coordination warning.
            // Full CC.COORD.1 failure is reserved for explicit R_k violation.
            // Log but continue.
        }
        Ok(())
    }

    // ─────────────────────────────────────────────────────────────────────
    // MASTER EQUATION  (T.FOUND.3)
    // ─────────────────────────────────────────────────────────────────────

    /// Apply the master equation to compute Δ_{k+1}.
    ///
    /// Δ_{k+1} = B_S^{-1}(Π_G(F_fold*(Σ_i ω_i N_i(B_S(Δ_k)) − ζ∇V))) + ξ_k
    ///
    /// Implementation order (preserves well-posedness per T.FOUND.3):
    /// 1. B_S(Δ_k) — substrate encode
    /// 2. Σ_i ω_i N_i(·) — weighted operator sum
    /// 3. − ζ∇V — anchor gradient subtraction
    /// 4. F_fold* — fold gate (identity if fold conditions not met)
    /// 5. Π_G — group projection
    /// 6. B_S^{-1} — substrate decode
    /// 7. + ξ_k — bounded explore perturbation (Δ_explore only)
    ///
    /// Register: T.FOUND.3, D.EXEC.1.
    fn apply_master_equation(&self, state: &WitnessState) -> Result<Delta, SaiosError> {
        let delta_k = &state.delta_k;
        let p = &self.params;

        // Step 1: B_S(Δ_k) — substrate encode all coordinates
        // For in-memory computation: encode then immediately decode (round-trip test).
        // The encoding is used to confirm substrate independence holds.
        let _encoded = self.substrate_encode_delta(delta_k)?;

        // Step 2: Compute coherence weights as i64 scores.
        // Chronometry v1.0: weights are selection (i64), not derivation (Q).
        // The Taylor-expanded Q omegas produced 97-digit denominators through
        // lcm compounding. i64 scores bound the denominator to score_total.
        let gamma_k = compute_gamma_k(delta_k);
        let omegas = self.compute_all_omegas(&gamma_k);
        // Project Q weights to i64 scores: scale to [0, 1000] range
        let scores: Vec<i64> = omegas.iter().map(|omega| {
            let scaled = omega * &Q::new(BigInt::from(1000), BigInt::from(1));
            scaled.numer().try_into().unwrap_or(0i64).max(0).min(1000)
        }).collect();
        let score_total: i64 = scores.iter().sum();

        // Step 3: Σ_i score_i * N_i(Δ_k) / score_total — i64-weighted operator sum
        let mut weighted_sum = Delta::zero(delta_k.dim, delta_k.m);
        let denom = Q::new(BigInt::from(score_total.max(1)), BigInt::from(1));
        for (i, op) in self.operators.iter().enumerate() {
            let s = scores[i];
            (s > 0).then(|| {
                let ni_delta = op.apply(delta_k).ok();
                ni_delta.map(|nd| {
                    let w = Q::new(BigInt::from(s), BigInt::from(1));
                    for row in 0..delta_k.dim {
                        for col in 0..delta_k.dim {
                            for l in 0..delta_k.m {
                                weighted_sum.entries[row][col][l] +=
                                    &w * &nd.entries[row][col][l];
                            }
                        }
                    }
                });
            });
        }
        // Single integer division: denominator = score_total (bounded i64)
        for row in 0..delta_k.dim {
            for col in 0..delta_k.dim {
                for l in 0..delta_k.m {
                    weighted_sum.entries[row][col][l] =
                        &weighted_sum.entries[row][col][l] / &denom;
                }
            }
        }

        // If no operators: identity (system at equilibrium, T_k → 0)
        if self.operators.is_empty() {
            return Ok(pi_g_project(delta_k));
        }

        // Step 4: − ζ∇V — subtract anchor gradient
        let grad_v = anchor_gradient(delta_k, &state.delta_bar);
        let mut after_anchor = Delta::zero(delta_k.dim, delta_k.m);
        for i in 0..delta_k.dim {
            for j in 0..delta_k.dim {
                for l in 0..delta_k.m {
                    after_anchor.entries[i][j][l] =
                        &weighted_sum.entries[i][j][l]
                        - &p.zeta * &grad_v.entries[i][j][l];
                }
            }
        }

        // Step 5: F_fold* — orbit-lock gate (T.13, D.6b)
        // Checks for torsion cycles before energy minimization.
        // If orbit lock exists: returns identity (veto fold, preserve information).
        // If no lock: fold permitted (Phase 2.1: identity; Phase 2.2: argmin C).
        let after_fold = fold::f_fold_star(&after_anchor, &self.operators, &self.params);

        // Step 6: Π_G — group projection
        let after_pi_g = pi_g_project(&after_fold);

        // Step 7: B_S^{-1} — substrate decode (no-op for Q representation)
        // In Q representation: B_S^{-1}(B_S(x)) = x exactly (T.FOUND.5).
        let after_decode = after_pi_g;

        // Step 8: + ξ_k — bounded stochastic perturbation to Δ_explore
        // For initial deployment: ξ_k = 0 (deterministic mode).
        // Production: add bounded Q-rational noise to explore coordinates only.
        let delta_k1 = after_decode;

        Ok(delta_k1)
    }

    // ─────────────────────────────────────────────────────────────────────
    // HELPER METHODS
    // ─────────────────────────────────────────────────────────────────────

    /// Compute ω_i for all operators. Register: D.MFA.WEIGHT.
    fn compute_all_omegas(&self, gamma_k: &Q) -> Vec<Q> {
        self.operators.iter().map(|op| {
            // α_1 = 0 for first operator (ω_1 ≡ 1). Others use α_i = α_gamma.
            let alpha = if op.id == 0 { Q::zero() } else { self.params.alpha_gamma.clone() };
            compute_omega(&alpha, gamma_k, &self.params.tau_lag)
        }).collect()
    }

    /// Substrate-encode all Δ_ij coordinates. Register: D.5.1-DIM.
    fn substrate_encode_delta(
        &self,
        delta: &Delta,
    ) -> Result<Vec<Vec<Vec<SubstrateCoord>>>, SaiosError> {
        let mut encoded = Vec::with_capacity(delta.dim);
        for i in 0..delta.dim {
            let mut row = Vec::with_capacity(delta.dim);
            for j in 0..delta.dim {
                let mut entry = Vec::with_capacity(delta.m);
                for l in 0..delta.m {
                    let coord = substrate_encode(
                        &delta.entries[i][j][l], &self.params.delta
                    )?;
                    entry.push(coord);
                }
                row.push(entry);
            }
            encoded.push(row);
        }
        Ok(encoded)
    }

}

#[cfg(test)]
mod tests {
    use super::*;

    fn qr(n: i64, d: i64) -> Q { Q::new(BigInt::from(n), BigInt::from(d)) }

    #[test]
    fn test_temporal_anchor_round_trip() {
        let mut delta = Delta::zero(3, 1);
        delta.set_antisym(0, 1, vec![qr(1042, 1000)]);
        delta.set_antisym(1, 2, vec![qr(542, 1000)]);
        delta.set_antisym(0, 2, vec![qr(1584, 1000)]);

        let bytes = delta.to_temporal_anchor();
        assert!(bytes.len() > 8);

        let restored = Delta::from_temporal_anchor(&bytes).expect("must deserialize");
        assert_eq!(restored.dim, 3);
        assert_eq!(restored.m, 1);
        for i in 0..3 {
            for j in 0..3 {
                assert_eq!(restored.entries[i][j][0], delta.entries[i][j][0],
                    "entry [{i}][{j}] must survive round-trip exactly");
            }
        }
        assert!(restored.verify_conservation());
    }

    #[test]
    fn test_temporal_anchor_large_numerators() {
        let mut delta = Delta::zero(3, 1);
        let big_n = BigInt::from(123456789012345i64);
        let big_d = BigInt::from(987654321i64);
        delta.set_antisym(0, 1, vec![Q::new(big_n.clone(), big_d.clone())]);
        delta.set_antisym(1, 2, vec![qr(1, 1)]);
        delta.set_antisym(0, 2, vec![Q::new(&big_n + BigInt::from(1), big_d)]);

        let bytes = delta.to_temporal_anchor();
        let restored = Delta::from_temporal_anchor(&bytes).expect("must deserialize");
        assert_eq!(restored.entries[0][1][0], delta.entries[0][1][0]);
        assert_eq!(restored.entries[1][0][0], delta.entries[1][0][0]);
        assert!(restored.verify_conservation());
    }

    #[test]
    fn test_temporal_anchor_zero_delta() {
        let delta = Delta::zero(3, 1);
        let bytes = delta.to_temporal_anchor();
        let restored = Delta::from_temporal_anchor(&bytes).expect("must deserialize");
        assert_eq!(restored.dim, 3);
        assert!(restored.verify_conservation());
        for i in 0..3 {
            for j in 0..3 { assert!(restored.entries[i][j][0].is_zero()); }
        }
    }

    #[test]
    fn test_temporal_anchor_rejects_corrupt_data() {
        assert!(Delta::from_temporal_anchor(&[]).is_none());
        assert!(Delta::from_temporal_anchor(&[0, 0, 0, 0, 0, 0, 0, 0]).is_none()); // dim=0
        assert!(Delta::from_temporal_anchor(&[3, 0, 0, 0, 1, 0, 0, 0]).is_none()); // 3x1 but truncated
        assert!(Delta::from_temporal_anchor(&[3, 0, 0, 0, 1, 0, 0, 0, 99]).is_none()); // bad sign byte
    }

    #[test]
    fn test_genesis_displacement_zero_at_genesis() {
        let genesis = Delta::zero(3, 1);
        let (drift, torsion) = genesis_displacement(&genesis, &genesis);
        assert!(drift.is_zero(), "no displacement at genesis");
        assert!(torsion.is_zero(), "no torsion at genesis");
    }

    #[test]
    fn test_genesis_displacement_measures_entry_drift() {
        let mut genesis = Delta::zero(3, 1);
        genesis.set_antisym(0, 1, vec![qr(1, 1)]);
        genesis.set_antisym(1, 2, vec![qr(1, 2)]);
        genesis.set_antisym(0, 2, vec![qr(3, 2)]);

        // Node 42: perturbed by 42/1000
        let mut evolved = Delta::zero(3, 1);
        evolved.set_antisym(0, 1, vec![qr(1042, 1000)]);
        evolved.set_antisym(1, 2, vec![qr(542, 1000)]);
        evolved.set_antisym(0, 2, vec![qr(1584, 1000)]);

        let (drift, torsion) = genesis_displacement(&evolved, &genesis);
        // drift = |1042/1000 - 1| + |542/1000 - 1/2| + |1584/1000 - 3/2|
        //       = |42/1000| + |42/1000| + |84/1000|
        //       = 42/1000 + 42/1000 + 84/1000 = 168/1000
        assert!(drift > Q::zero(), "evolved node must have positive drift");
        // Both are cocycle-consistent → torsion = C(evolved) = 0
        assert!(torsion.is_zero(), "cocycle-consistent evolution has zero torsion");
    }

    #[test]
    fn test_genesis_displacement_different_nodes_different_drift() {
        let mut genesis = Delta::zero(3, 1);
        genesis.set_antisym(0, 1, vec![qr(1, 1)]);
        genesis.set_antisym(1, 2, vec![qr(1, 2)]);
        genesis.set_antisym(0, 2, vec![qr(3, 2)]);

        let mut node1 = Delta::zero(3, 1);
        node1.set_antisym(0, 1, vec![qr(1001, 1000)]);
        node1.set_antisym(1, 2, vec![qr(501, 1000)]);
        node1.set_antisym(0, 2, vec![qr(1502, 1000)]);

        let mut entity_42 = Delta::zero(3, 1);
        entity_42.set_antisym(0, 1, vec![qr(1042, 1000)]);
        entity_42.set_antisym(1, 2, vec![qr(542, 1000)]);
        entity_42.set_antisym(0, 2, vec![qr(1584, 1000)]);

        let (drift1, _) = genesis_displacement(&node1, &genesis);
        let (drift42, _) = genesis_displacement(&entity_42, &genesis);

        assert!(drift42 > drift1, "node 42 has larger perturbation → larger drift");
    }

    #[test]
    fn test_genome_solved_puzzles_round_trip() {
        let genesis = Delta::zero(3, 1);
        let mut genome = Genome::new(1, 1, &genesis);

        genome.record_solved_puzzle([0x00, 0x7b, 0xbf, 0xb7]);
        genome.record_solved_puzzle([0x55, 0x82, 0xe5, 0xca]);
        genome.record_solved_puzzle([0x00, 0x7b, 0xbf, 0xb7]); // duplicate — dissolves

        assert_eq!(genome.solved_puzzles.len(), 2);

        let bytes = genome.to_bytes();
        let restored = Genome::from_bytes(&bytes).unwrap();
        assert_eq!(restored.solved_puzzles.len(), 2);
        assert_eq!(restored.solved_puzzles[0], [0x00, 0x7b, 0xbf, 0xb7]);
        assert_eq!(restored.solved_puzzles[1], [0x55, 0x82, 0xe5, 0xca]);
    }

    #[test]
    fn test_genome_solved_puzzles_backwards_compatible() {
        // Old genome without solved_puzzles section should deserialize fine
        let genesis = Delta::zero(3, 1);
        let old_genome = Genome::new(1, 1, &genesis);
        let old_bytes = old_genome.to_bytes();
        // Trim the solved_puzzles section (last byte = count 0)
        let trimmed = &old_bytes[..old_bytes.len() - 1];
        let restored = Genome::from_bytes(trimmed).unwrap();
        assert!(restored.solved_puzzles.is_empty());
    }
}
